export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Range start ${from} exceeds end ${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Comma-separated list — recurse on each part and flatten
  if (expression.includes(",")) {
    const parts = expression.split(",");
    const values = parts.flatMap((part) => parseField(part.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (expression === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (expression.includes("/")) {
    const [rangePart, stepPart] = expression.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in expression: ${expression}`);
    }

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [fromStr, toStr] = rangePart.split("-");
        start = clamp(parseInt(fromStr, 10), min, max);
        end = clamp(parseInt(toStr, 10), min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expression.includes("-")) {
    const [fromStr, toStr] = expression.split("-");
    const from = clamp(parseInt(fromStr, 10), min, max);
    const to = clamp(parseInt(toStr, 10), min, max);
    return range(from, to);
  }

  // Single number
  const value = parseInt(expression, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid cron expression field: ${expression}`);
  }
  return [clamp(value, min, max)];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 cron fields but got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.tokens = Math.min(this.maxTokens, this.tokens + tokensToAdd);
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens to consume must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested ${tokens} tokens exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const waitMs = this.estimateWaitMs(tokens);
      await sleep(Math.max(waitMs, 1));
    }
  }

  private estimateWaitMs(tokens: number): number {
    this.refill();
    const deficit = tokens - this.tokens;

    if (deficit <= 0) return 0;

    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const timeUntilNextInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);

    return timeUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
  }
}

function sleep(ms: number): Promise<void> {
  return new Promise((resolve) => setTimeout(resolve, ms));
}

export default RateLimiter;

export interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in expression "${context}"`
    );
  }
}

function parseStep(expr: string, min: number, max: number): number[] {
  const slashIdx = expr.indexOf('/');
  const rangeExpr = expr.slice(0, slashIdx);
  const stepStr   = expr.slice(slashIdx + 1);

  const step = Number(stepStr);
  if (!Number.isInteger(step) || step < 1) {
    throw new RangeError(`Invalid step value "${stepStr}" — must be a positive integer`);
  }

  let rangeMin: number;
  let rangeMax: number;

  if (rangeExpr === '*') {
    rangeMin = min;
    rangeMax = max;
  } else if (rangeExpr.includes('-')) {
    [rangeMin, rangeMax] = parseRangeBounds(rangeExpr, min, max);
  } else {
    const start = Number(rangeExpr);
    if (!Number.isInteger(start)) {
      throw new TypeError(`Invalid start value "${rangeExpr}" in step expression`);
    }
    assertInRange(start, min, max, expr);
    rangeMin = start;
    rangeMax = max;
  }

  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) {
    values.push(v);
  }
  return values;
}

function parseRangeBounds(expr: string, min: number, max: number): [number, number] {
  const dashIdx = expr.indexOf('-');
  if (dashIdx < 1) {
    throw new TypeError(`Invalid range expression "${expr}"`);
  }
  const startStr = expr.slice(0, dashIdx);
  const endStr   = expr.slice(dashIdx + 1);

  const start = Number(startStr);
  const end   = Number(endStr);

  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new TypeError(`Non-integer bound(s) in range "${expr}"`);
  }

  assertInRange(start, min, max, expr);
  assertInRange(end,   min, max, expr);

  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in "${expr}"`);
  }

  return [start, end];
}

function parseField(expr: string, min: number, max: number): number[] {
  if (typeof expr !== 'string' || expr.trim() === '') {
    throw new TypeError(`Field expression must be a non-empty string, got: ${JSON.stringify(expr)}`);
  }

  // Comma-separated list — split first, resolve each atom independently
  if (expr.includes(',')) {
    const seen = new Set<number>();
    for (const atom of expr.split(',')) {
      const trimmed = atom.trim();
      if (trimmed === '') {
        throw new TypeError(`Empty element in comma list "${expr}"`);
      }
      for (const v of parseField(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  // Wildcard
  if (expr === '*') {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Step expression (*/n or start/n or start-end/n)
  if (expr.includes('/')) {
    return parseStep(expr, min, max);
  }

  // Range (e.g., 1-5)
  if (expr.includes('-')) {
    const [start, end] = parseRangeBounds(expr, min, max);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single numeric value
  const num = Number(expr);
  if (!Number.isInteger(num)) {
    throw new TypeError(`Non-integer value "${expr}"`);
  }
  assertInRange(num, min, max, expr);
  return [num];
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new RangeError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${parts.length}`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = parts;
  const r = FIELD_RANGES;

  return {
    minute:     parseField(minuteExpr, r.minute.min,     r.minute.max),
    hour:       parseField(hourExpr,   r.hour.min,       r.hour.max),
    dayOfMonth: parseField(domExpr,    r.dayOfMonth.min, r.dayOfMonth.max),
    month:      parseField(monthExpr,  r.month.min,      r.month.max),
    dayOfWeek:  parseField(dowExpr,    r.dayOfWeek.min,  r.dayOfWeek.max),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? (JSON.stringify(val) as Primitive) : (val as Primitive);
    }
  }
  return result;
}

export default flattenObject;

