type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedValue = Primitive | Date | RegExp | Array<unknown> | { [key: string]: NestedValue };

function isPlainObject(value: unknown): value is Record<string, NestedValue> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  obj: Record<string, NestedValue>,
  prefix: string,
  seen: WeakSet<object>,
  result: Record<string, unknown>
): void {
  if (seen.has(obj)) {
    throw new TypeError(
      `Circular reference detected at key path: "${prefix || "(root)"}"`
    );
  }
  seen.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0 && prefix !== "") {
    // Preserve empty objects as leaf values rather than silently dropping the key
    result[prefix] = {};
    seen.delete(obj);
    return;
  }

  for (const [key, value] of entries) {
    if (key.includes(".")) {
      // Dot-containing keys would corrupt round-trip fidelity — flag it clearly
      throw new TypeError(
        `Key "${key}" contains a dot, which would produce ambiguous flattened output`
      );
    }

    const flatKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flatten(value, flatKey, seen, result);
    } else {
      // Arrays, Dates, RegExps, primitives — all treated as opaque leaf values
      result[flatKey] = value;
    }
  }

  seen.delete(obj);
}

function flattenObject(obj: Record<string, NestedValue>): Record<string, unknown> {
  if (!isPlainObject(obj)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        obj === null ? "null" : typeof obj
      }`
    );
  }

  const result: Record<string, unknown> = {};
  flatten(obj, "", new WeakSet(), result);
  return result;
}

export default flattenObject;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: unknown) => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: WaitEntry[] = [];
  private checkScheduled = false;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;
    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }
    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0 && this.refillRate > 0) {
      const added = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    }
    this.lastRefillTime = now;
  }

  tryConsume(tokens = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number")
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    this.applyRefill();

    // Fast path: queue is empty and bucket has sufficient tokens
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    // Detect requests that can never be fulfilled due to zero refill rate
    if (this.refillRate === 0) {
      return Promise.reject(
        new Error(
          `Cannot fulfill request for ${tokens} tokens: bucket is depleted and refillRate is 0`
        )
      );
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleNextCheck();
    });
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const entry = this.waitQueue[0]!;
      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        entry.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextCheck(): void {
    if (this.checkScheduled || this.waitQueue.length === 0) return;
    if (this.refillRate <= 0) return;

    const entry = this.waitQueue[0]!;
    const needed = Math.max(0, entry.tokens - this.currentTokens);
    const msPerToken = this.refillIntervalMs / this.refillRate;
    // Add a small buffer (+1ms) to avoid firing just before enough tokens arrive
    const delayMs = needed === 0 ? 0 : Math.ceil(needed * msPerToken) + 1;

    this.checkScheduled = true;

    const tick = () => {
      this.checkScheduled = false;
      this.applyRefill();
      this.drainQueue();
      this.scheduleNextCheck();
    };

    if (delayMs === 0) {
      // Defer to the next microtask to avoid reentrancy within the same call
      Promise.resolve().then(tick);
    } else {
      setTimeout(tick, delayMs);
    }
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] | unknown };
type FlatObject = { [key: string]: Primitive };

function isPlainObject(value: unknown): value is NestedObject {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flatten(
  input: unknown,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  if (isPlainObject(input)) {
    if (seen.has(input as object)) {
      result[prefix] = "[Circular]";
      return;
    }

    const keys = Object.keys(input as object);

    if (keys.length === 0) {
      if (prefix !== "") result[prefix] = {};
      return;
    }

    seen.add(input as object);

    for (const key of keys) {
      if (!Object.prototype.hasOwnProperty.call(input, key)) continue;
      const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;
      flatten((input as NestedObject)[key], nextPrefix, result, seen);
    }

    seen.delete(input as object);
  } else if (Array.isArray(input)) {
    if (seen.has(input)) {
      result[prefix] = "[Circular]";
      return;
    }

    if (input.length === 0) {
      if (prefix !== "") result[prefix] = [];
      return;
    }

    seen.add(input);

    for (let i = 0; i < input.length; i++) {
      const nextPrefix = prefix === "" ? String(i) : `${prefix}.${i}`;
      flatten(input[i], nextPrefix, result, seen);
    }

    seen.delete(input);
  } else {
    if (prefix !== "") result[prefix] = input as Primitive;
  }
}

export default function flattenObject(input: unknown): FlatObject {
  if (input === null || input === undefined) return {};
  if (!isPlainObject(input) && !Array.isArray(input)) return {};

  const result: FlatObject = {};
  const seen = new WeakSet<object>();
  flatten(input, "", result, seen);
  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? JSON.stringify(val) : (val as Primitive);
    }
  }
  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => i + from);
}

function assertInRange(val: number, min: number, max: number, ctx: string): void {
  if (val < min || val > max)
    throw new RangeError(`${ctx}: ${val} out of [${min},${max}]`);
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // wildcard
  if (segment === "*") return range(min, max);

  // step: */N or R-R/N
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    if (!stepStr || stepStr === "") throw new SyntaxError(`Missing step in: ${segment}`);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new RangeError(`Invalid step: ${stepStr}`);

    let base: number[];
    if (left === "*") {
      base = range(min, max);
    } else if (left.includes("-")) {
      const [a, b] = left.split("-").map(Number);
      if (isNaN(a) || isNaN(b)) throw new SyntaxError(`Invalid range in step: ${left}`);
      assertInRange(a, min, max, field);
      assertInRange(b, min, max, field);
      base = range(a, b);
    } else {
      const start = parseInt(left, 10);
      if (isNaN(start)) throw new SyntaxError(`Invalid step base: ${left}`);
      assertInRange(start, min, max, field);
      base = range(start, max);
    }

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // range: N-N
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Invalid range: ${segment}`);
    const [a, b] = parts.map(Number);
    if (isNaN(a) || isNaN(b)) throw new SyntaxError(`Non-numeric range: ${segment}`);
    assertInRange(a, min, max, field);
    assertInRange(b, min, max, field);
    return range(a, b);
  }

  // single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new SyntaxError(`Non-numeric value: ${segment}`);
  assertInRange(val, min, max, field);
  return [val];
}

function parseField(expr: string, field: CronField): number[] {
  const segments = expr.split(",");
  if (segments.length === 0 || segments.some((s) => s === ""))
    throw new SyntaxError(`Empty segment in field ${field}: ${expr}`);

  const values = new Set<number>();
  for (const seg of segments) {
    for (const v of parseSegment(seg.trim(), field)) values.add(v);
  }

  return [...values].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or x-y/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    const base =
      rangePart === "*"
        ? range(min, max)
        : parseSegment(rangePart, min, max);

    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Range: x-y
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: ${segment}`);
    if (start > end) throw new Error(`Range start > end: ${segment}`);
    return clamp(range(start, end), min, max);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < min || val > max) throw new Error(`Value ${val} out of range [${min}, ${max}]`);
  return [val];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const fieldNames: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const result = {} as CronResult;
  for (let i = 0; i < 5; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(fields[i], min, max);
  }

  return result;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise<void>((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.currentTokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const waitMs = Math.max(
          1,
          intervalsNeeded * this.refillIntervalMs -
            (Date.now() - this.lastRefillTime) % this.refillIntervalMs
        );

        setTimeout(attempt, waitMs);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const [key, value] of entries) {
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(val: number, min: number, max: number, ctx: string): void {
  if (val < min || val > max)
    throw new RangeError(`${ctx}: ${val} out of [${min},${max}]`);
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    if (!stepStr || stepStr === "")
      throw new SyntaxError(`${field}: missing step in "${segment}"`);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0)
      throw new RangeError(`${field}: step must be positive integer, got "${stepStr}"`);

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map((v) => parseInt(v, 10));
      if (isNaN(s) || isNaN(e)) throw new SyntaxError(`${field}: bad range "${rangePart}"`);
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      base = range(s, e);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new SyntaxError(`${field}: bad step base "${rangePart}"`);
      assertInRange(start, min, max, field);
      base = range(start, max);
    }
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new SyntaxError(`${field}: invalid range "${segment}"`);
    const [s, e] = parts.map((v) => parseInt(v, 10));
    if (isNaN(s) || isNaN(e)) throw new SyntaxError(`${field}: non-numeric range "${segment}"`);
    assertInRange(s, min, max, field);
    assertInRange(e, min, max, field);
    return range(s, e);
  }

  // Number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new SyntaxError(`${field}: unrecognized token "${segment}"`);
  assertInRange(val, min, max, field);
  return [val];
}

function parseField(expr: string, field: CronField): number[] {
  if (!expr || expr.trim() === "")
    throw new SyntaxError(`${field}: empty field`);

  const segments = expr.split(",");
  const values = new Set<number>();

  for (const seg of segments) {
    const trimmed = seg.trim();
    if (!trimmed) throw new SyntaxError(`${field}: empty segment in "${expr}"`);
    for (const v of parseSegment(trimmed, field)) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string")
    throw new TypeError(`parseCron: expression must be string`);

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(`parseCron: expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter((v) => v >= min && v <= max))].sort(
    (a, b) => a - b
  );
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or x/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let start = min;
    let end = max;
    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }
    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return clamp(values, min, max);
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: x-y
  if (segment.includes("-")) {
    const [s, e] = segment.split("-").map(Number);
    if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range: ${segment}`);
    if (s > e) throw new Error(`Range start > end: ${segment}`);
    return clamp(range(s, e), min, max);
  }

  // Number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${segment}`);
  return clamp([n], min, max);
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma list
  const parts = field.split(",");
  if (parts.length > 1) {
    const values = parts.flatMap((p) => parseSegment(p.trim(), min, max));
    return clamp(values, min, max);
  }
  return parseSegment(field.trim(), min, max);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;
  const fieldKeys: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];
  const raws = [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw];

  const result = {} as CronResult;
  for (let i = 0; i < 5; i++) {
    const key = fieldKeys[i];
    const [min, max] = FIELD_RANGES[key];
    result[key] = parseField(raws[i], min, max);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = value as Primitive | Array<unknown>;
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function rangeArray(min: number, max: number): number[] {
  const result: number[] = [];
  for (let i = min; i <= max; i++) result.push(i);
  return result;
}

function assertInRange(value: number, min: number, max: number, field: CronField): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step value: */N or R-S/N
  if (segment.includes("/")) {
    const [rangePart, stepPart] = segment.split("/");
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value "${stepPart}" in field "${field}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      assertInRange(lo, min, max, field);
      assertInRange(hi, min, max, field);
      if (lo > hi) throw new Error(`Invalid range "${rangePart}" in field "${field}"`);
      start = lo;
      end = hi;
    } else {
      start = parseInt(rangePart, 10);
      assertInRange(start, min, max, field);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: N-M
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) {
      throw new Error(`Invalid range "${segment}" in field "${field}"`);
    }
    assertInRange(lo, min, max, field);
    assertInRange(hi, min, max, field);
    if (lo > hi) throw new Error(`Invalid range "${segment}" in field "${field}"`);
    return rangeArray(lo, hi);
  }

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid value "${segment}" in field "${field}"`);
  }

  // dayOfWeek: treat 7 as Sunday (0)
  const normalized = field === "dayOfWeek" && value === 7 ? 0 : value;
  assertInRange(normalized, min, max, field);
  return [normalized];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  const values = new Set<number>();

  for (const segment of segments) {
    const trimmed = segment.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${field}"`);
    for (const v of parseSegment(trimmed, field)) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private waitQueue: Array<{
    tokens: number;
    resolve: () => void;
  }>;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    if (intervals > 0) {
      const added = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private msUntilTokens(tokens: number): number {
    if (this.currentTokens >= tokens) return 0;
    const needed = tokens - this.currentTokens;
    const intervalsNeeded = Math.ceil(needed / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const msUntilNextInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);
    return msUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(`tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );

    this.lazyRefill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleRefillCheck();
    });
  }

  private scheduleRefillCheck(): void {
    if (this.waitQueue.length === 0) return;

    const next = this.waitQueue[0];
    const delay = this.msUntilTokens(next.tokens);

    setTimeout(() => {
      this.lazyRefill();
      this.drainQueue();
      if (this.waitQueue.length > 0) {
        this.scheduleRefillCheck();
      }
    }, Math.max(1, delay));
  }
}

