type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  seen = new WeakSet<object>(),
  maxDepth = 50,
  currentDepth = 0
): FlatObject {
  if (obj === null || typeof obj !== "object") {
    return prefix ? { [prefix]: obj as Primitive } : {};
  }

  if (currentDepth > maxDepth) {
    return prefix ? { [prefix]: "[MaxDepthExceeded]" } : {};
  }

  if (seen.has(obj)) {
    return prefix ? { [prefix]: "[Circular]" } : {};
  }

  seen.add(obj);

  const result: FlatObject = {};

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) {
      result[prefix] = Array.isArray(obj) ? [] : {};
    }
    seen.delete(obj);
    return result;
  }

  for (const [key, value] of entries) {
    if (key === "" || key.includes(".")) {
      // Keys that are empty or contain dots would produce ambiguous output;
      // escape them by wrapping in brackets so round-tripping remains possible.
      const safeKey = `[${key}]`;
      const fullKey = prefix ? `${prefix}.${safeKey}` : safeKey;

      if (
        value !== null &&
        typeof value === "object" &&
        !Array.isArray(value)
      ) {
        const nested = flattenObject(
          value as NestedObject,
          fullKey,
          seen,
          maxDepth,
          currentDepth + 1
        );
        Object.assign(result, nested);
      } else {
        result[fullKey] = value as Primitive | unknown[];
      }
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp)
    ) {
      const nested = flattenObject(
        value as NestedObject,
        fullKey,
        seen,
        maxDepth,
        currentDepth + 1
      );
      Object.assign(result, nested);
    } else {
      result[fullKey] = value as Primitive | unknown[];
    }
  }

  seen.delete(obj);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const safeKey = String(key);
    if (safeKey.includes("\0")) continue; // reject null-byte poisoned keys

    const newPrefix = prefix ? `${prefix}.${safeKey}` : safeKey;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newPrefix, result);
    } else if (Array.isArray(value)) {
      result[newPrefix] = JSON.stringify(value);
    } else {
      result[newPrefix] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject | unknown,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (typeof obj !== "object" || obj instanceof Date) {
    if (prefix) result[prefix] = obj instanceof Date ? obj.toISOString() : (obj as Primitive);
    return result;
  }

  if (Array.isArray(obj)) {
    if (obj.length === 0) {
      if (prefix) result[prefix] = null;
    } else {
      for (let i = 0; i < obj.length; i++) {
        flattenObject(
          obj[i] as NestedObject,
          prefix ? `${prefix}.${i}` : `${i}`,
          result
        );
      }
    }
    return result;
  }

  const entries = Object.entries(obj as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix) result[prefix] = null;
    return result;
  }

  for (const [key, value] of entries) {
    if (key.includes(".")) throw new Error(`Key "${key}" contains reserved character "."`);
    const newKey = prefix ? `${prefix}.${key}` : key;
    flattenObject(value as NestedObject, newKey, result);
  }

  return result;
}

export default flattenObject;

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type CronFieldName = keyof CronResult;

interface FieldConfig {
  min: number;
  max: number;
}

const FIELD_ORDER: CronFieldName[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

const FIELD_CONFIG: Record<CronFieldName, FieldConfig> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function parseInteger(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Expected a non-negative integer but got "${raw}" in "${context}"`);
  }
  const n = Number(raw);
  if (!Number.isFinite(n) || !Number.isInteger(n)) {
    throw new Error(`Overflow or non-integer value "${raw}" in "${context}"`);
  }
  return n;
}

function assertInRange(value: number, config: FieldConfig, context: string): void {
  if (value < config.min || value > config.max) {
    throw new Error(
      `Value ${value} is out of valid range [${config.min}–${config.max}] in "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function parseToken(token: string, config: FieldConfig): number[] {
  if (token === "") {
    throw new Error("Encountered an empty cron token");
  }

  // Wildcard
  if (token === "*") {
    return expandRange(config.min, config.max, 1);
  }

  // Comma-separated list — split first to prevent misidentifying inner operators
  if (token.includes(",")) {
    const parts = token.split(",");
    const seen = new Set<number>();
    for (const part of parts) {
      const trimmed = part.trim();
      if (trimmed === "") {
        throw new Error(`Empty element in comma-separated list "${token}"`);
      }
      for (const v of parseToken(trimmed, config)) {
        seen.add(v);
      }
    }
    return [...seen].sort((a, b) => a - b);
  }

  // Step value: */n, start/n, or start-end/n
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const left = token.slice(0, slashIdx);
    const stepRaw = token.slice(slashIdx + 1);

    const step = parseInteger(stepRaw, token);
    if (step === 0) {
      throw new Error(`Step value must be >= 1 in "${token}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (left === "*") {
      rangeStart = config.min;
      rangeEnd = config.max;
    } else if (left.includes("-")) {
      const dashIdx = left.indexOf("-");
      const startRaw = left.slice(0, dashIdx);
      const endRaw = left.slice(dashIdx + 1);
      rangeStart = parseInteger(startRaw, token);
      rangeEnd = parseInteger(endRaw, token);
      assertInRange(rangeStart, config, token);
      assertInRange(rangeEnd, config, token);
      if (rangeStart > rangeEnd) {
        throw new Error(`Range start (${rangeStart}) > end (${rangeEnd}) in "${token}"`);
      }
    } else {
      rangeStart = parseInteger(left, token);
      assertInRange(rangeStart, config, token);
      rangeEnd = config.max;
    }

    return expandRange(rangeStart, rangeEnd, step);
  }

  // Range: n-m
  if (token.includes("-")) {
    const dashIdx = token.indexOf("-");
    const startRaw = token.slice(0, dashIdx);
    const endRaw = token.slice(dashIdx + 1);

    // Guard against malformed tokens like "1-2-3"
    if (endRaw.includes("-")) {
      throw new Error(`Malformed range "${token}" — too many dashes`);
    }

    const start = parseInteger(startRaw, token);
    const end = parseInteger(endRaw, token);
    assertInRange(start, config, token);
    assertInRange(end, config, token);
    if (start > end) {
      throw new Error(`Range start (${start}) > end (${end}) in "${token}"`);
    }
    return expandRange(start, end, 1);
  }

  // Single number
  const num = parseInteger(token, token);
  assertInRange(num, config, token);
  return [num];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (got ${fields.length}): "${expression}"`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    const config = FIELD_CONFIG[fieldName];
    let values = parseToken(fields[i], config);

    // Normalise dayOfWeek: 7 is a widely-used alias for 0 (Sunday)
    if (fieldName === "dayOfWeek") {
      const normalised = new Set(values.map(v => (v === 7 ? 0 : v)));
      values = [...normalised].sort((a, b) => a - b);
    }

    result[fieldName] = values;
  }

  return result;
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private waitQueue: Array<{ tokens: number; resolve: () => void }>;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (next === undefined) break;

      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(`tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );

    this.refill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleRefillCheck();
    });
  }

  private scheduleRefillCheck(): void {
    if (this.waitQueue.length === 0) return;

    const msPerToken = this.refillIntervalMs / this.refillRate;
    const first = this.waitQueue[0];
    if (first === undefined) return;

    const deficit = first.tokens - this.currentTokens;
    const waitMs = Math.ceil(deficit * msPerToken);

    setTimeout(() => {
      this.refill();
      this.drainQueue();

      if (this.waitQueue.length > 0) {
        this.scheduleRefillCheck();
      }
    }, Math.max(0, waitMs));
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] };
type FlatObject = { [key: string]: Primitive | unknown[] };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
