  if (obj === null || obj === undefined) return result;
  if (typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive | unknown[];
    return result;
  }

  const keys = Object.keys(obj);
  if (keys.length === 0) {
    if (prefix) result[prefix] = {};
    return result;
  }

  for (const key of keys) {
    // Reject keys that would corrupt dot-path semantics
    if (key === "") continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      !(val instanceof Date) &&
      !(val instanceof RegExp)
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = val as Primitive | unknown[];
    }
  }

  return result;
}

