interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waiters: Waiter[];
  private scheduledRefill: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a positive finite number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waiters = [];
    this.scheduledRefill = null;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    const refilled = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);

    if (refilled > this.currentTokens) {
      this.currentTokens = refilled;
    }

    this.lastRefillTime = now;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`tokens must be a positive finite number, got ${tokens}`);
    }
    if (tokens > this.maxTokens) {
      return false;
    }

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainWaiters();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      return Promise.reject(
        new RangeError(`tokens must be a positive finite number, got ${tokens}`)
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) can never be satisfied: exceeds maxTokens (${this.maxTokens})`
        )
      );
    }

    return new Promise<void>((resolve) => {
      if (this.tryConsume(tokens)) {
        resolve();
        return;
      }

      this.waiters.push({ tokens, resolve });
      this.scheduleNextWake();
    });
  }

  private msUntilTokens(needed: number): number {
    const deficit = needed - this.currentTokens;
    if (deficit <= 0) return 0;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleNextWake(): void {
    if (this.scheduledRefill !== null || this.waiters.length === 0) return;

    this.applyRefill();

    const nextWaiter = this.waiters[0];
    const delay = this.msUntilTokens(nextWaiter.tokens);

    if (delay <= 0) {
      this.drainWaiters();
      return;
    }

    this.scheduledRefill = setTimeout(() => {
      this.scheduledRefill = null;
      this.drainWaiters();
    }, delay);
  }

  private drainWaiters(): void {
    this.applyRefill();

    while (this.waiters.length > 0) {
      const waiter = this.waiters[0];

      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waiters.shift();
        waiter.resolve();
      } else {
        break;
      }
    }

    if (this.waiters.length > 0) {
      this.scheduleNextWake();
    }
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = key.includes(".") ? `[${key}]` : key;
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step: */n or x-y/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s;
        end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (start < min || end > max || start > end)
      throw new Error(`Range ${start}-${end} out of bounds [${min},${max}]`);

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (segment === "*") return range(min, max);

  // Range: x-y
  if (segment.includes("-")) {
    const [s, e] = segment.split("-").map(Number);
    if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range: ${segment}`);
    if (s < min || e > max || s > e)
      throw new Error(`Range ${s}-${e} out of bounds [${min},${max}]`);
    return range(s, e);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${segment}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of bounds [${min},${max}]`);
  return [n];
}

function parseField(field: string, min: number, max: number): number[] {
  if (field.includes(",")) {
    const parts = field.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseSegment(part.trim(), min, max)) values.add(v);
    }
    return [...values].sort((a, b) => a - b);
  }
  return parseSegment(field, min, max);
}

function normalizeWeekday(values: number[]): number[] {
  // Treat 7 as 0 (Sunday)
  const normalized = new Set(values.map((v) => (v === 7 ? 0 : v)));
  return [...normalized].sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;
  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  const parsed = fieldNames.map((name, i) => {
    const { min, max } = FIELD_RANGES[name];
    return parseField(fields[i], min, max);
  });

  return {
    minute: parsed[0],
    hour: parsed[1],
    dayOfMonth: parsed[2],
    month: parsed[3],
    dayOfWeek: normalizeWeekday(parsed[4]),
  };
}

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldSpec {
  min: number;
  max: number;
  parseMax?: number; // for alias support (e.g. DOW 7 = Sunday)
}

const FIELD_SPECS: Readonly<Record<keyof CronFields, FieldSpec>> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6, parseMax: 7 }, // 7 = Sunday alias
} as const;

function makeRange(start: number, end: number): number[] {
  if (start > end) throw new Error(`Start ${start} exceeds end ${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInBounds(value: number, spec: FieldSpec, context: string): void {
  const ceiling = spec.parseMax ?? spec.max;
  if (!Number.isInteger(value) || value < spec.min || value > ceiling) {
    throw new Error(
      `Value ${value} out of valid range [${spec.min}–${ceiling}] in "${context}"`
    );
  }
}

function parseToken(token: string, spec: FieldSpec): number[] {
  // Wildcard
  if (token === '*') return makeRange(spec.min, spec.max);

  // Step: */n or a-b/n or a/n
  if (token.includes('/')) {
    const slashIndex = token.indexOf('/');
    const baseExpr = token.slice(0, slashIndex);
    const stepStr  = token.slice(slashIndex + 1);

    const step = Number(stepStr);
    if (!Number.isInteger(step) || step <= 0) {
      throw new Error(`Invalid step "${stepStr}" in "${token}"`);
    }

    let start: number;
    let end: number;

    if (baseExpr === '*') {
      start = spec.min;
      end   = spec.max;
    } else if (baseExpr.includes('-')) {
      [start, end] = parseRangeBounds(baseExpr, spec);
    } else {
      const n = Number(baseExpr);
      if (!Number.isInteger(n)) throw new Error(`Invalid base "${baseExpr}" in "${token}"`);
      assertInBounds(n, spec, token);
      start = n;
      end   = spec.max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Range: a-b
  if (token.includes('-')) {
    const [start, end] = parseRangeBounds(token, spec);
    return makeRange(start, end);
  }

  // Bare integer
  const value = Number(token);
  if (!Number.isInteger(value) || token.trim() === '') {
    throw new Error(`Cannot parse "${token}" as an integer`);
  }
  assertInBounds(value, spec, token);
  return [value];
}

function parseRangeBounds(expr: string, spec: FieldSpec): [number, number] {
  const dashIndex = expr.indexOf('-');
  if (dashIndex <= 0) throw new Error(`Malformed range "${expr}"`);

  const startStr = expr.slice(0, dashIndex);
  const endStr   = expr.slice(dashIndex + 1);

  const start = Number(startStr);
  const end   = Number(endStr);

  if (!Number.isInteger(start) || !Number.isInteger(end)) {
    throw new Error(`Non-integer bounds in range "${expr}"`);
  }

  assertInBounds(start, spec, expr);
  assertInBounds(end,   spec, expr);

  if (start > end) throw new Error(`Range start ${start} > end ${end} in "${expr}"`);

  return [start, end];
}

function parseField(expression: string, spec: FieldSpec): number[] {
  if (!expression || expression.trim() === '') {
    throw new Error('Field expression must not be empty');
  }

  const parts = expression.split(',');
  if (parts.length === 0) throw new Error(`Empty comma list in "${expression}"`);

  const seen = new Set<number>();

  for (const raw of parts) {
    const part = raw.trim();
    if (part === '') throw new Error(`Empty token in comma list "${expression}"`);
    for (const v of parseToken(part, spec)) seen.add(v);
  }

  return Array.from(seen).sort((a, b) => a - b);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // In many cron implementations, 7 is a Sunday alias for 0.
  const normalized = new Set(values.map(v => (v === 7 ? 0 : v)));
  return Array.from(normalized).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const trimmed = expression.trim();
  if (trimmed === '') throw new Error('Cron expression must not be empty');

  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (got ${tokens.length}): "${trimmed}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = tokens;

  type FieldEntry = { key: keyof CronFields; expr: string };

  const fields: FieldEntry[] = [
    { key: 'minute',     expr: minuteExpr },
    { key: 'hour',       expr: hourExpr   },
    { key: 'dayOfMonth', expr: domExpr    },
    { key: 'month',      expr: monthExpr  },
    { key: 'dayOfWeek',  expr: dowExpr    },
  ];

  const result = {} as CronFields;

  for (const { key, expr } of fields) {
    const spec = FIELD_SPECS[key];
    try {
      const values = parseField(expr, spec);
      result[key] = key === 'dayOfWeek' ? normalizeDayOfWeek(values) : values;
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      throw new Error(`Invalid "${key}" field ("${expr}"): ${message}`);
    }
  }

  return result;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a finite positive number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a finite non-negative number");
    }
    if (
      !Number.isFinite(options.refillIntervalMs) ||
      options.refillIntervalMs <= 0
    ) {
      throw new RangeError("refillIntervalMs must be a finite positive number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed < this.refillIntervalMs || this.refillRate === 0) {
      return;
    }

    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);
    // Guard against overflow when refillRate * intervalsElapsed exceeds safe integer range
    const tokensToAdd = Math.min(
      this.maxTokens,
      intervalsElapsed * this.refillRate
    );

    this.currentTokens = Math.min(
      this.maxTokens,
      this.currentTokens + tokensToAdd
    );
    // Advance lastRefillTime by whole intervals only — preserves fractional interval progress
    this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return true;
    // A request exceeding the bucket capacity can never be satisfied
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a finite non-negative number");
    }
    if (tokens === 0) return;
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens} — ` +
          `this can never be satisfied`
      );
    }

    while (!this.tryConsume(tokens)) {
      // After a failed tryConsume, applyRefill() has already run so
      // currentTokens reflects the present state.

      if (this.refillRate === 0) {
        // Tokens will never arrive; fail fast rather than block forever.
        throw new Error(
          `Deadlock: refillRate is 0 and only ${this.currentTokens} tokens ` +
            `are available (${tokens} required)`
        );
      }

      const needed = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(needed / this.refillRate);
      const elapsedSinceLastRefill = Date.now() - this.lastRefillTime;
      const msUntilNextRefill = this.refillIntervalMs - elapsedSinceLastRefill;
      // Full wait: time to next refill tick + any additional whole intervals
      const waitMs =
        msUntilNextRefill + (intervalsNeeded - 1) * this.refillIntervalMs;

      await new Promise<void>((resolve) =>
        setTimeout(resolve, Math.max(1, waitMs))
      );
      // Re-enter the loop; tryConsume will refill and re-check.
      // Concurrent waiters may race — whoever wins tryConsume holds the tokens;
      // the rest loop and re-calculate their wait naturally.
    }
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: NestedObject | Primitive | unknown[] | Date | RegExp };
type FlatObject = { [key: string]: unknown };

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  const proto = Object.getPrototypeOf(value);
  return proto === Object.prototype || proto === null;
}

function flattenObject(
  input: unknown,
  prefix = "",
  seen = new WeakSet<object>(),
  result: FlatObject = {}
): FlatObject {
  if (!isPlainObject(input)) {
    if (prefix !== "") result[prefix] = input;
    return result;
  }

  if (seen.has(input as object)) {
    if (prefix !== "") result[prefix] = "[Circular]";
    return result;
  }

  seen.add(input as object);

  const entries = Object.entries(input as Record<string, unknown>);

  if (entries.length === 0) {
    if (prefix !== "") result[prefix] = input;
    seen.delete(input as object);
    return result;
  }

  for (const [key, value] of entries) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const fullKey = prefix === "" ? key : `${prefix}.${key}`;

    if (isPlainObject(value)) {
      flattenObject(value, fullKey, seen, result);
    } else {
      result[fullKey] = value;
    }
  }

  seen.delete(input as object);
  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervalsElapsed * this.refillRate
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(`tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`)
      );
    }

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = intervalsNeeded * this.refillIntervalMs;

        setTimeout(attempt, Math.max(delay, 1));
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[] = [];
  private drainScheduled: boolean = false;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `refillRate must be a positive finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime = now;
    }
  }

  private validateTokenCount(tokens: number, caller: string): void {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(
        `${caller}: tokens must be a non-negative finite number, got ${tokens}`
      );
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenCount(tokens, "tryConsume");

    // A request that can never be satisfied should fail immediately and
    // deterministically rather than silently blocking forever if someone
    // later calls waitForTokens with the same value.
    if (tokens > this.maxTokens) {
      return false;
    }

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Immediately service any waiters that can now be satisfied.
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    this.validateTokenCount(tokens, "waitForTokens");

    // Reject upfront — these tokens can *never* accumulate; waiting would
    // block forever with no way to signal the caller.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}`
        )
      );
    }

    this.lazyRefill();

    // Skip the queue only when it is empty to preserve FIFO ordering among
    // concurrent waiters and prevent a stream of small requests from
    // starving a large one that arrived earlier.
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextDrain();
    });
  }

  private scheduleNextDrain(): void {
    // Guard: only one pending drain timer at a time.
    if (this.drainScheduled || this.waitQueue.length === 0) return;

    const nextWaiter = this.waitQueue[0];
    this.lazyRefill();

    const tokensNeeded = nextWaiter.tokens - this.currentTokens;

    // Already satisfiable — defer to the next microtask so callers receive
    // their Promise before resolve() fires, avoiding confusing synchronous
    // resolution when waitForTokens is called in a tight loop.
    const delayMs =
      tokensNeeded <= 0
        ? 0
        : Math.ceil(
            tokensNeeded * (this.refillIntervalMs / this.refillRate)
          );

    this.drainScheduled = true;
    setTimeout(() => {
      this.drainScheduled = false;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.lazyRefill();

    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift();
        waiter.resolve();
      } else {
        // Cannot satisfy the head-of-queue waiter yet; schedule the next
        // drain for exactly when it will become satisfiable.
        break;
      }
    }

    if (this.waitQueue.length > 0) {
      this.scheduleNextDrain();
    }
  }
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_ORDER: CronField[] = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
];

function buildRange(start: number, end: number): number[] {
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function assertInBounds(
  value: number,
  min: number,
  max: number,
  context: string,
): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of bounds [${min}-${max}] in "${context}"`,
    );
  }
}

function parseSegment(
  segment: string,
  field: CronField,
  min: number,
  max: number,
): number[] {
  // Step expression: */n  |  x/n  |  x-y/n
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const baseExpr = segment.slice(0, slashIdx);
    const stepStr  = segment.slice(slashIdx + 1);
    const step = Number(stepStr);

    if (!Number.isInteger(step) || step <= 0) {
      throw new TypeError(
        `Invalid step "${stepStr}" in field "${field}" segment "${segment}"`,
      );
    }

    let rangeStart: number;
    let rangeEnd:   number;

    if (baseExpr === "*") {
      rangeStart = min;
      rangeEnd   = max;
    } else if (baseExpr.includes("-")) {
      [rangeStart, rangeEnd] = parseBoundedRange(baseExpr, field, min, max);
    } else {
      rangeStart = Number(baseExpr);
      assertInBounds(rangeStart, min, max, segment);
      rangeEnd = max;
    }

    const out: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) out.push(i);
    return out;
  }

  // Wildcard
  if (segment === "*") return buildRange(min, max);

  // Range: x-y
  if (segment.includes("-")) {
    const [start, end] = parseBoundedRange(segment, field, min, max);
    return buildRange(start, end);
  }

  // Single integer
  const num = Number(segment);
  if (!Number.isInteger(num) || String(num) !== segment.trim()) {
    throw new TypeError(
      `Invalid token "${segment}" in field "${field}"`,
    );
  }
  assertInBounds(num, min, max, segment);
  return [num];
}

function parseBoundedRange(
  expr: string,
  field: CronField,
  min: number,
  max: number,
): [number, number] {
  const dashIdx = expr.indexOf("-");
  if (dashIdx <= 0) {
    throw new SyntaxError(`Malformed range "${expr}" in field "${field}"`);
  }
  const start = Number(expr.slice(0, dashIdx));
  const end   = Number(expr.slice(dashIdx + 1));

  assertInBounds(start, min, max, expr);
  assertInBounds(end,   min, max, expr);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${field}"`,
    );
  }
  return [start, end];
}

function parseField(raw: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  if (typeof raw !== "string" || raw.trim() === "") {
    throw new TypeError(`Empty or invalid value for field "${field}"`);
  }

  // Comma-separated list — each part is parsed independently then merged
  if (raw.includes(",")) {
    const seen = new Set<number>();
    for (const part of raw.split(",")) {
      const trimmed = part.trim();
      if (trimmed === "") {
        throw new SyntaxError(
          `Empty token in comma list for field "${field}": "${raw}"`,
        );
      }
      for (const v of parseSegment(trimmed, field, min, max)) seen.add(v);
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(raw.trim(), field, min, max);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new TypeError("Cron expression must not be empty");
  }

  const parts = trimmed.split(/\s+/);
  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected exactly 5 fields, got ${parts.length}: "${trimmed}"`,
    );
  }

  const result = {} as CronExpression;
  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const field = FIELD_ORDER[i];
    result[field] = parseField(parts[i], field);
  }
  return result;
}

const FIELD_RANGES = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

interface CronResult {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
}

function range(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => i + min);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter(v => v >= min && v <= max);
}

function parseField(token: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // comma-separated list — recurse
  if (token.includes(",")) {
    const values = token
      .split(",")
      .flatMap(t => parseField(t.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // step: */n or start-end/n
  if (token.includes("/")) {
    const [rangePart, stepStr] = token.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in "${token}"`);

    let start = min;
    let end   = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [s, e] = rangePart.split("-").map(Number);
        start = s; end = e;
      } else {
        start = parseInt(rangePart, 10);
      }
    }

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range in "${token}"`);

    const result: number[] = [];
    for (let v = start; v <= end; v += step) result.push(v);
    return clamp(result, min, max);
  }

  // range: start-end
  if (token.includes("-")) {
    const [s, e] = token.split("-").map(Number);
    if (isNaN(s) || isNaN(e) || s > e) throw new Error(`Invalid range "${token}"`);
    return clamp(range(s, e), min, max);
  }

  // wildcard
  if (token === "*") return range(min, max);

  // single number
  const n = parseInt(token, 10);
  if (isNaN(n)) throw new Error(`Invalid token "${token}" for field ${field}`);
  if (n < min || n > max) throw new Error(`Value ${n} out of range [${min},${max}] for field ${field}`);
  return [n];
}

export default function parseCron(expr: string): CronResult {
  const fields = expr.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = fields;

  return {
    minute:     parseField(minuteToken, "minute"),
    hour:       parseField(hourToken,   "hour"),
    dayOfMonth: parseField(domToken,    "dayOfMonth"),
    month:      parseField(monthToken,  "month"),
    dayOfWeek:  parseField(dowToken,    "dayOfWeek"),
  };
}

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      this.tokens = Math.min(
        this.maxTokens,
        this.tokens + intervalsElapsed * this.refillRate
      );
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<keyof CronFields, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

const FIELD_ORDER = [
  "minute",
  "hour",
  "dayOfMonth",
  "month",
  "dayOfWeek",
] as const;

function parseStrictInt(raw: string, context: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new SyntaxError(`Invalid integer "${raw}" in ${context}`);
  }
  const n = parseInt(raw, 10);
  if (!Number.isSafeInteger(n)) {
    throw new RangeError(`Integer "${raw}" exceeds safe range in ${context}`);
  }
  return n;
}

function assertInRange(value: number, { min, max }: FieldRange, field: string): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} out of valid range [${min}, ${max}] for field "${field}"`
    );
  }
}

function expandRange(min: number, max: number, step: number): number[] {
  if (step <= 0) {
    throw new RangeError(`Step must be a positive integer, got ${step}`);
  }
  const values: number[] = [];
  for (let i = min; i <= max; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(
  segment: string,
  range: FieldRange,
  field: string
): number[] {
  const context = `field "${field}"`;

  // Step expression: */n, m/n, m-n/p
  if (segment.includes("/")) {
    const slashIdx = segment.indexOf("/");
    const rangePart = segment.slice(0, slashIdx);
    const stepPart = segment.slice(slashIdx + 1);

    if (stepPart.includes("/")) {
      throw new SyntaxError(`Multiple "/" in segment "${segment}" for ${context}`);
    }

    const step = parseStrictInt(stepPart, context);
    if (step === 0) {
      throw new RangeError(`Step value cannot be zero in ${context}`);
    }

    if (rangePart === "*") {
      return expandRange(range.min, range.max, step);
    }

    if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      if (rangePart.split("-").length !== 2) {
        throw new SyntaxError(`Invalid range "${rangePart}" in ${context}`);
      }
      const start = parseStrictInt(startStr, context);
      const end   = parseStrictInt(endStr,   context);
      assertInRange(start, range, field);
      assertInRange(end,   range, field);
      if (start > end) {
        throw new RangeError(
          `Range start ${start} exceeds end ${end} in ${context}`
        );
      }
      return expandRange(start, end, step);
    }

    // Bare number/step: n/step — from n to max
    const start = parseStrictInt(rangePart, context);
    assertInRange(start, range, field);
    return expandRange(start, range.max, step);
  }

  // Range: m-n
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in ${context}`);
    }
    const start = parseStrictInt(parts[0], context);
    const end   = parseStrictInt(parts[1], context);
    assertInRange(start, range, field);
    assertInRange(end,   range, field);
    if (start > end) {
      throw new RangeError(
        `Range start ${start} exceeds end ${end} in ${context}`
      );
    }
    return expandRange(start, end, 1);
  }

  // Wildcard
  if (segment === "*") {
    return expandRange(range.min, range.max, 1);
  }

  // Single value
  const value = parseStrictInt(segment, context);
  assertInRange(value, range, field);
  return [value];
}

function parseField(raw: string, range: FieldRange, field: string): number[] {
  if (raw.trim() === "") {
    throw new SyntaxError(`Empty value for field "${field}"`);
  }

  const parts = raw.split(",");
  if (parts.some((p) => p === "")) {
    throw new SyntaxError(
      `Trailing or consecutive commas in field "${field}"`
    );
  }

  const seen = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part, range, field)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(
      `parseCron expects a string, received ${typeof expression}`
    );
  }

  const trimmed = expression.trim();
  if (trimmed === "") {
    throw new SyntaxError("Cron expression must not be empty");
  }

  const tokens = trimmed.split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const name = FIELD_ORDER[i];
    result[name] = parseField(tokens[i], FIELD_RANGES[name], name);
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | unknown[] | Date | RegExp | object;
};

type FlatObject = Record<string, unknown>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (Array.isArray(value)) return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (value instanceof Error) return false;
  if (value instanceof ArrayBuffer) return false;
  if (ArrayBuffer.isView(value)) return false;
  return true;
}

function flattenInternal(
  input: Record<string, unknown>,
  prefix: string,
  result: FlatObject,
  seen: WeakSet<object>
): void {
  for (const key of Object.keys(input)) {
    if (!Object.prototype.hasOwnProperty.call(input, key)) continue;

    const fullKey = prefix.length > 0 ? `${prefix}.${key}` : key;
    const value = input[key];

    if (isPlainObject(value)) {
      if (seen.has(value)) {
        // Circular reference detected — treat the node as a leaf to avoid infinite recursion
        result[fullKey] = "[Circular]";
        continue;
      }

      const childKeys = Object.keys(value as Record<string, unknown>);
      if (childKeys.length === 0) {
        // Empty plain object — preserve as leaf so the key is not silently dropped
        result[fullKey] = value;
        continue;
      }

      seen.add(value);
      flattenInternal(value as Record<string, unknown>, fullKey, result, seen);
      seen.delete(value);
    } else {
      result[fullKey] = value;
    }
  }
}

export default function flattenObject(input: unknown): FlatObject {
  if (!isPlainObject(input)) {
    throw new TypeError(
      `flattenObject expects a plain object, received: ${
        input === null ? "null" : typeof input
      }`
    );
  }

  const result: FlatObject = {};
  const seen = new WeakSet<object>();
  seen.add(input);
  flattenInternal(input, "", result, seen);
  return result;
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  const out: number[] = [];
  for (let i = from; i <= to; i++) out.push(i);
  return out;
}

function clamp(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter((v) => v >= min && v <= max))].sort(
    (a, b) => a - b
  );
}

function parseSegment(seg: string, min: number, max: number): number[] {
  // step: */n or a-b/n
  if (seg.includes("/")) {
    const [base, stepStr] = seg.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);
    const [from, to] =
      base === "*" ? [min, max] : base.split("-").map(Number);
    const values: number[] = [];
    for (let i = from; i <= to; i += step) values.push(i);
    return clamp(values, min, max);
  }

  // list: 1,3,5
  if (seg.includes(",")) {
    const values = seg.split(",").map((s) => {
      const n = parseInt(s.trim(), 10);
      if (isNaN(n)) throw new Error(`Invalid value: ${s}`);
      return n;
    });
    return clamp(values, min, max);
  }

  // range: 1-5
  if (seg.includes("-")) {
    const [from, to] = seg.split("-").map(Number);
    if (isNaN(from) || isNaN(to)) throw new Error(`Invalid range: ${seg}`);
    return clamp(range(from, to), min, max);
  }

  // wildcard
  if (seg === "*") return range(min, max);

  // number
  const n = parseInt(seg, 10);
  if (isNaN(n)) throw new Error(`Invalid token: ${seg}`);
  return clamp([n], min, max);
}

export default function parseCron(expr: string): CronResult {
  const fields = expr.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys: CronField[] = [
    "minute",
    "hour",
    "dayOfMonth",
    "month",
    "dayOfWeek",
  ];

  return Object.fromEntries(
    keys.map((key, i) => {
      const [min, max] = FIELD_RANGES[key];
      return [key, parseSegment(fields[i], min, max)];
    })
  ) as CronResult;
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface WaitEntry {
  tokens: number;
  resolve: () => void;
  reject: (err: Error) => void;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTimestamp: number;
  private readonly waitQueue: WaitEntry[];
  private drainScheduled: boolean;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0) {
      throw new RangeError(`refillRate must be a finite positive number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTimestamp = Date.now();
    this.waitQueue = [];
    this.drainScheduled = false;
  }

  private applyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTimestamp;
    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTimestamp = now;
  }

  /** Milliseconds until at least `needed` tokens will be available (from now). */
  private msUntilAvailable(needed: number): number {
    this.applyRefill();
    if (this.currentTokens >= needed) return 0;
    const deficit = needed - this.currentTokens;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleDrain(delayMs: number): void {
    if (this.drainScheduled) return;
    this.drainScheduled = true;
    setTimeout(() => {
      this.drainScheduled = false;
      this.drainQueue();
    }, delayMs);
  }

  private drainQueue(): void {
    this.applyRefill();

    while (this.waitQueue.length > 0) {
      const entry = this.waitQueue[0];

      if (this.currentTokens >= entry.tokens) {
        this.currentTokens -= entry.tokens;
        this.waitQueue.shift();
        entry.resolve();
        // Re-apply refill between resolutions so timing stays accurate
        // for subsequent entries over long queues.
        this.applyRefill();
      } else {
        const delay = this.msUntilAvailable(entry.tokens);
        this.scheduleDrain(delay === 0 ? 1 : delay);
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a finite non-negative number, got ${tokens}`);
    }
    if (tokens === 0) return true;
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTimestamp = Date.now();
    // Give already-waiting callers a chance to proceed.
    if (this.waitQueue.length > 0) {
      this.drainQueue();
    }
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a finite non-negative number, got ${tokens}`)
      );
    }
    if (tokens === 0) return Promise.resolve();
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} token(s) exceeds bucket capacity of ${this.maxTokens}; ` +
            `this request can never be satisfied`
        )
      );
    }

    // Fast path: serve immediately if queue is empty and tokens are available.
    if (this.waitQueue.length === 0) {
      this.applyRefill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });

      if (!this.drainScheduled) {
        const delay = this.msUntilAvailable(tokens);
        this.scheduleDrain(delay === 0 ? 1 : delay);
      }
    });
  }
}

