type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function parseField(expr: string, min: number, max: number): number[] {
  const all = () => Array.from({ length: max - min + 1 }, (_, i) => i + min);

  // Comma list — recurse
  if (expr.includes(",")) {
    const values = expr.split(",").flatMap(part => parseField(part.trim(), min, max));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Step: */n or start-end/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        rangeMin = lo;
        rangeMax = hi;
      } else {
        rangeMin = parseInt(rangePart, 10);
      }
    }

    validate(rangeMin, min, max);
    validate(rangeMax, min, max);

    const result: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) result.push(v);
    return result;
  }

  // Wildcard
  if (expr === "*") return all();

  // Range: n-m
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(Number);
    validate(lo, min, max);
    validate(hi, min, max);
    if (lo > hi) throw new Error(`Invalid range: ${expr}`);
    return Array.from({ length: hi - lo + 1 }, (_, i) => i + lo);
  }

  // Single number
  const n = parseInt(expr, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${expr}`);
  validate(n, min, max);
  return [n];
}

function validate(n: number, min: number, max: number): void {
  if (n < min || n > max) throw new Error(`Value ${n} out of range [${min}, ${max}]`);
}

function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const keys: CronField[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return keys.reduce((acc, key, i) => {
    const [min, max] = FIELD_RANGES[key];
    acc[key] = parseField(fields[i], min, max);
    return acc;
  }, {} as CronResult);
}

export default parseCron;

