interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface Waiter {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Waiter[];
  private checkScheduled: boolean;

  constructor(options: RateLimiterOptions) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(
        `maxTokens must be a positive finite number, got ${maxTokens}`
      );
    }
    if (!Number.isFinite(refillRate) || refillRate <= 0) {
      throw new RangeError(
        `refillRate must be a positive finite number, got ${refillRate}`
      );
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(
        `refillIntervalMs must be a positive finite number, got ${refillIntervalMs}`
      );
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.checkScheduled = false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervalsElapsed = Math.floor(elapsed / this.refillIntervalMs);

    if (intervalsElapsed > 0) {
      const tokensToAdd = intervalsElapsed * this.refillRate;
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      // Advance anchor only by whole intervals consumed to preserve partial-interval progress
      this.lastRefillTime += intervalsElapsed * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(
        `tokens must be a positive finite number, got ${tokens}`
      );
    }

    // A request larger than the bucket can never be granted
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    // Unblock any queued waiters that can now be served
    this.processQueue();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(
        `tokens must be a positive finite number, got ${tokens}`
      );
    }
    if (tokens > this.maxTokens) {
      throw new RangeError(
        `Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens}); ` +
          `this request can never be fulfilled`
      );
    }

    this.refill();

    // Fast path: no queue contention and sufficient tokens available
    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return;
    }

    // Slow path: enqueue and wait for a scheduled refill tick to serve us
    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleRefillCheck();
    });
  }

  private processQueue(): void {
    // Drain the front of the queue in FIFO order; stop at the first waiter
    // that cannot yet be served to prevent head-of-line starvation inversion
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0];
      if (this.currentTokens >= waiter.tokens) {
        this.currentTokens -= waiter.tokens;
        this.waitQueue.shift(); // remove before resolving to keep queue consistent
        waiter.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleRefillCheck(): void {
    // Only one live timer at a time; it reschedules itself if the queue is still non-empty
    if (this.checkScheduled || this.waitQueue.length === 0) return;

    this.checkScheduled = true;

    const nextWaiter = this.waitQueue[0];
    const tokensNeeded = nextWaiter.tokens - this.currentTokens;

    let delayMs: number;

    if (tokensNeeded <= 0) {
      // Tokens are already available (race with another consumer); fire ASAP
      delayMs = 0;
    } else {
      // Compute minimum intervals required to accumulate the deficit
      const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);
      // Time remaining in the current (partially elapsed) interval
      const elapsedInInterval =
        (Date.now() - this.lastRefillTime) % this.refillIntervalMs;
      const timeUntilNextInterval =
        this.refillIntervalMs - elapsedInInterval;
      // Total wait = remainder of current interval + any additional full intervals
      delayMs =
        timeUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
      // Small buffer (+1 ms) to absorb timer imprecision and avoid a spurious early wake
      delayMs = Math.max(0, delayMs) + 1;
    }

    setTimeout(() => {
      this.checkScheduled = false;
      this.refill();
      this.processQueue();
      // If the queue still has waiters (e.g. more tokens needed), reschedule
      if (this.waitQueue.length > 0) {
        this.scheduleRefillCheck();
      }
    }, delayMs);
  }
}

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 7 },
} as const;

type FieldName = keyof typeof FIELD_RANGES;

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or x-y/n
  if (segment.includes("/")) {
    const [rangepart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let start: number;
    let end: number;

    if (rangepart === "*") {
      start = min;
      end = max;
    } else if (rangepart.includes("-")) {
      const [s, e] = rangepart.split("-").map(Number);
      start = clamp(s, min, max);
      end = clamp(e, min, max);
      if (start > end) throw new Error(`Invalid range: ${rangepart}`);
    } else {
      start = clamp(parseInt(rangepart, 10), min, max);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: x-y
  if (segment.includes("-")) {
    const [s, e] = segment.split("-").map(Number);
    const start = clamp(s, min, max);
    const end = clamp(e, min, max);
    if (start > end) throw new Error(`Invalid range: ${segment}`);
    return range(start, end);
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${segment}`);
  return [clamp(n, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  const parts = field.split(",");
  const values = new Set<number>();

  for (const part of parts) {
    for (const v of parseSegment(part.trim(), min, max)) {
      values.add(v);
    }
  }

  return Array.from(values).sort((a, b) => a - b);
}

function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  const dayOfWeekValues = parseField(dowStr, FIELD_RANGES.dayOfWeek.min, FIELD_RANGES.dayOfWeek.max);
  // Normalize 7 (Sunday alt) to 0
  const normalizedDow = Array.from(
    new Set(dayOfWeekValues.map((v) => (v === 7 ? 0 : v)))
  ).sort((a, b) => a - b);

  return {
    minute: parseField(minuteStr, FIELD_RANGES.minute.min, FIELD_RANGES.minute.max),
    hour: parseField(hourStr, FIELD_RANGES.hour.min, FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domStr, FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month: parseField(monthStr, FIELD_RANGES.month.min, FIELD_RANGES.month.max),
    dayOfWeek: normalizedDow,
  };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined | bigint | symbol;

type NestedObject = {
  [key: string]: Primitive | NestedObject | Array<unknown>;
};

type FlattenedObject = Record<string, Primitive | Array<unknown>>;

function flattenObject(
  input: unknown,
  prefix = "",
  seen = new WeakSet<object>()
): FlattenedObject {
  if (input === null || input === undefined) {
    return prefix ? { [prefix]: input as Primitive } : {};
  }

  if (typeof input !== "object" || Array.isArray(input)) {
    return prefix ? { [prefix]: input as Primitive | Array<unknown> } : {};
  }

  if (seen.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix || "(root)"}"`
    );
  }

  seen.add(input as object);

  const obj = input as Record<string, unknown>;
  const keys = Object.keys(obj);

  if (keys.length === 0) {
    return prefix ? { [prefix]: {} as unknown as Primitive } : {};
  }

  const result: FlattenedObject = {};

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      const nested = flattenObject(value, fullKey, seen);
      Object.assign(result, nested);
    } else {
      result[fullKey] = value as Primitive | Array<unknown>;
    }
  }

  seen.delete(input as object);

  return result;
}

