type NestedObject = {
  [key: string]: Scalar | NestedObject | NestedObject[];
};

type FlattenedObject = Record<string, Scalar>;

function isTraversable(value: unknown): value is Record<string, unknown> | unknown[] {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map || value instanceof Set) return false;
  if (value instanceof ArrayBuffer || ArrayBuffer.isView(value)) return false;
  return true;
}

function flattenInto(
  input: Record<string, unknown> | unknown[],
  prefix: string,
  result: FlattenedObject,
  seen: WeakSet<object>
): void {
  if (seen.has(input)) {
    throw new TypeError(
      `Circular reference detected${prefix ? ` at key "${prefix}"` : ""}`
    );
  }

  seen.add(input);

  const entries = Array.isArray(input)
    ? input.map((v, i) => [String(i), v] as const)
    : Object.entries(input);

  for (const [key, value] of entries) {
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;

    if (isTraversable(value)) {
      const nested = value as Record<string, unknown> | unknown[];
      const isEmpty = Array.isArray(nested)
        ? nested.length === 0
        : Object.keys(nested).length === 0;

      if (isEmpty) {
        result[fullKey] = Array.isArray(nested) ? ([] as unknown as Scalar) : ({} as unknown as Scalar);
      } else {
        flattenInto(nested, fullKey, result, seen);
      }
    } else {
      result[fullKey] = value as Scalar;
    }
  }

  seen.delete(input);
}

function flattenObject(obj: NestedObject | Record<string, unknown>): FlattenedObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    throw new TypeError("Input must be a non-null, non-array object");
  }

  const result: FlattenedObject = {};
  const seen = new WeakSet<object>();
  flattenInto(obj as Record<string, unknown>, "", result, seen);
  return result;
}

export default flattenObject;

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private waitQueue: Array<{
    tokens: number;
    resolve: () => void;
    reject: (err: Error) => void;
  }> = [];

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private lazyRefill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed <= 0) return;

    const intervalsElapsed = elapsed / this.refillIntervalMs;
    const tokensToAdd = intervalsElapsed * this.refillRate;

    if (tokensToAdd >= 1 || this.currentTokens < this.maxTokens) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + tokensToAdd
      );
      this.lastRefillTime = now;
    }
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens <= 0)
      throw new RangeError("tokens must be a finite positive number");
    if (tokens > this.maxTokens) return false;

    this.lazyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.lazyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens <= 0)
      return Promise.reject(
        new RangeError("tokens must be a finite positive number")
      );
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError("tokens requested exceeds maxTokens — will never resolve")
      );

    this.lazyRefill();

    if (this.waitQueue.length === 0 && this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve, reject) => {
      this.waitQueue.push({ tokens, resolve, reject });
      this.scheduleRefillCheck();
    });
  }

  private scheduleRefillCheck(): void {
    if (this.waitQueue.length === 0) return;

    const next = this.waitQueue[0];
    const deficit = next.tokens - this.currentTokens;

    const tokensPerMs = this.refillRate / this.refillIntervalMs;
    if (tokensPerMs <= 0) return;

    const waitMs = Math.ceil(deficit / tokensPerMs);
    const safeWait = Math.max(1, waitMs);

    setTimeout(() => {
      this.lazyRefill();
      this.drainQueue();
      if (this.waitQueue.length > 0) {
        this.scheduleRefillCheck();
      }
    }, safeWait);
  }
}

export default RateLimiter;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) return result;

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      !(val instanceof Date) &&
      !(val instanceof RegExp)
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = val as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: Record<string, Primitive> = {}
): Record<string, Primitive> {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(value) ? JSON.stringify(value) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function clamp(values: number[], min: number, max: number, field: CronField): number[] {
  for (const v of values) {
    if (v < min || v > max) {
      throw new Error(`Value ${v} out of range [${min},${max}] for field "${field}"`);
    }
  }
  return [...new Set(values)].sort((a, b) => a - b);
}

function parseSegment(segment: string, min: number, max: number, field: CronField): number[] {
  // wildcard
  if (segment === "*") return range(min, max);

  // step: */n or start-end/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step "${stepStr}" in field "${field}"`);

    let start: number;
    let end: number;
    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      const [s, e] = base.split("-").map(Number);
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range "${base}" in field "${field}"`);
      start = s;
      end = e;
    } else {
      start = parseInt(base, 10);
      if (isNaN(start)) throw new Error(`Invalid step base "${base}" in field "${field}"`);
      end = max;
    }

    const vals: number[] = [];
    for (let i = start; i <= end; i += step) vals.push(i);
    return clamp(vals, min, max, field);
  }

  // range: n-m
  if (segment.includes("-")) {
    const [s, e] = segment.split("-").map(Number);
    if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range "${segment}" in field "${field}"`);
    return clamp(range(s, e), min, max, field);
  }

  // single number
  const v = parseInt(segment, 10);
  if (isNaN(v)) throw new Error(`Invalid value "${segment}" in field "${field}"`);
  return clamp([v], min, max, field);
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // comma list — split first, then parse each segment
  const parts = expr.split(",");
  if (parts.length > 1) {
    const vals = parts.flatMap((p) => parseSegment(p.trim(), min, max, field));
    return clamp(vals, min, max, field);
  }

  return parseSegment(expr.trim(), min, max, field);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new Error("Expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  return Array.from({ length: end - start + 1 }, (_, i) => i + start);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];
  const all = range(min, max);

  if (segment === "*") return all;

  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step in: ${segment}`);
    const pool = base === "*" ? all : parseSegment(base, field);
    return pool.filter((v) => (v - pool[0]) % step === 0);
  }

  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end) || start > end)
      throw new Error(`Invalid range: ${segment}`);
    return clamp(range(start, end), min, max);
  }

  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new Error(`Invalid value: ${segment}`);
  if (val < min || val > max)
    throw new Error(`Value ${val} out of range [${min}, ${max}] for ${field}`);
  return [val];
}

function parseField(expr: string, field: CronField): number[] {
  const parts = expr.split(",");
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), field)) values.add(v);
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minute, hour, dayOfMonth, month, dayOfWeek] = (
    ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as CronField[]
  ).map((field, i) => parseField(fields[i], field));

  return { minute, hour, dayOfMonth, month, dayOfWeek };
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private checkScheduled: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError("maxTokens must be a positive finite number");
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError("refillRate must be a non-negative finite number");
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError("refillIntervalMs must be a positive finite number");
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.checkScheduled = false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    // Guard against backward clock drift
    if (elapsed <= 0) return;
    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const added = intervals * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
    // Advance lastRefillTime to the most recent completed interval boundary,
    // preserving sub-interval elapsed time so it accumulates correctly.
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError("tokens must be a non-negative finite number");
    }
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
    // If waiters remain (unlikely after full reset, but possible with
    // a concurrent tryConsume stealing tokens), reschedule.
    this.scheduleNextCheck();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number")
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds the maximum bucket capacity of ${this.maxTokens}; ` +
            `this promise can never be fulfilled`
        )
      );
    }
    if (tokens === 0) return Promise.resolve();

    // Fast path: only attempt immediate consumption when the queue is empty,
    // so existing waiters are not starved by new arrivals.
    if (this.waitQueue.length === 0) {
      this.refill();
      if (this.currentTokens >= tokens) {
        this.currentTokens -= tokens;
        return Promise.resolve();
      }
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleNextCheck();
    });
  }

  // Resolve queued waiters in FIFO order as long as current tokens allow.
  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];
      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        next.resolve();
      } else {
        break;
      }
    }
  }

  private scheduleNextCheck(): void {
    // Only one pending timeout at a time.
    if (this.checkScheduled || this.waitQueue.length === 0) return;

    // If refillRate is zero, tokens will never refill automatically.
    // Waiters will unblock only via an external reset() call.
    if (this.refillRate === 0) return;

    const next = this.waitQueue[0];
    const tokensNeeded = next.tokens - this.currentTokens;

    // How many full refill intervals are required to accumulate enough tokens?
    const intervalsNeeded = Math.ceil(tokensNeeded / this.refillRate);

    // Time remaining until the *next* refill tick fires.
    const elapsedInCurrentInterval = Date.now() - this.lastRefillTime;
    const msUntilNextTick = Math.max(
      0,
      this.refillIntervalMs - elapsedInCurrentInterval
    );

    // Total delay: wait for the first tick, then (intervalsNeeded - 1) more.
    const delay = msUntilNextTick + (intervalsNeeded - 1) * this.refillIntervalMs;

    this.checkScheduled = true;

    setTimeout(() => {
      this.checkScheduled = false;
      this.refill();
      this.drainQueue();
      // Recurse: there may still be waiters that need more tokens.
      this.scheduleNextCheck();
    }, delay);
  }
}

export default RateLimiter;

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  min: number;
  max: number;
  name: string;
};

const FIELD_CONFIGS = [
  { min: 0, max: 59, name: "minute" },
  { min: 0, max: 23, name: "hour" },
  { min: 1, max: 31, name: "dayOfMonth" },
  { min: 1, max: 12, name: "month" },
  { min: 0, max: 6, name: "dayOfWeek" },
] as const satisfies readonly FieldConfig[];

function assertInRange(value: number, config: FieldConfig): void {
  if (!Number.isInteger(value) || value < config.min || value > config.max) {
    throw new RangeError(
      `Value ${value} is out of range [${config.min}, ${config.max}] for field "${config.name}"`
    );
  }
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { min, max } = config;

  if (segment === "") {
    throw new SyntaxError(`Empty segment in field "${config.name}"`);
  }

  // Step: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const parts = segment.split("/");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid step expression "${segment}" in field "${config.name}"`);
    }
    const [rangeStr, stepStr] = parts;
    const step = Number(stepStr);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Invalid step "${stepStr}" in field "${config.name}"; must be a positive integer`);
    }

    let start: number;
    let end: number;

    if (rangeStr === "*") {
      start = min;
      end = max;
    } else if (rangeStr.includes("-")) {
      const rangeParts = rangeStr.split("-");
      if (rangeParts.length !== 2) {
        throw new SyntaxError(`Invalid range "${rangeStr}" in field "${config.name}"`);
      }
      start = Number(rangeParts[0]);
      end = Number(rangeParts[1]);
      assertInRange(start, config);
      assertInRange(end, config);
      if (start > end) {
        throw new RangeError(`Range start ${start} exceeds end ${end} in field "${config.name}"`);
      }
    } else {
      start = Number(rangeStr);
      assertInRange(start, config);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Range: n-m
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) {
      throw new SyntaxError(`Invalid range "${segment}" in field "${config.name}"`);
    }
    const start = Number(parts[0]);
    const end = Number(parts[1]);
    assertInRange(start, config);
    assertInRange(end, config);
    if (start > end) {
      throw new RangeError(`Range start ${start} exceeds end ${end} in field "${config.name}"`);
    }
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Single value
  const value = Number(segment);
  if (!Number.isInteger(value)) {
    throw new SyntaxError(`Non-integer value "${segment}" in field "${config.name}"`);
  }
  assertInRange(value, config);
  return [value];
}

function parseField(token: string, config: FieldConfig): number[] {
  if (typeof token !== "string" || token.trim() === "") {
    throw new SyntaxError(`Missing or empty token for field "${config.name}"`);
  }

  // Comma-separated list — each element is parsed independently and may itself be a range or step
  if (token.includes(",")) {
    const segments = token.split(",");
    const valueSet = new Set<number>();
    for (const segment of segments) {
      if (segment === "") {
        throw new SyntaxError(`Empty element in comma list for field "${config.name}"`);
      }
      for (const v of parseSegment(segment, config)) {
        valueSet.add(v);
      }
    }
    return [...valueSet].sort((a, b) => a - b);
  }

  return parseSegment(token, config);
}

export default function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const tokens = expression.trim().split(/\s+/);

  if (tokens.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek); got ${tokens.length}`
    );
  }

  const [minuteToken, hourToken, domToken, monthToken, dowToken] = tokens;

  return {
    minute: parseField(minuteToken, FIELD_CONFIGS[0]),
    hour: parseField(hourToken, FIELD_CONFIGS[1]),
    dayOfMonth: parseField(domToken, FIELD_CONFIGS[2]),
    month: parseField(monthToken, FIELD_CONFIGS[3]),
    dayOfWeek: parseField(dowToken, FIELD_CONFIGS[4]),
  };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) throw new RangeError("tokens exceeds maxTokens capacity");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
