interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`${context}: value ${value} out of range [${min}, ${max}]`);
  }
}

function parseNumber(token: string, min: number, max: number, context: string): number {
  const n = Number(token);
  if (!Number.isInteger(n) || isNaN(n)) {
    throw new SyntaxError(`${context}: "${token}" is not a valid integer`);
  }
  assertInRange(n, min, max, context);
  return n;
}

function expandRange(min: number, max: number): number[] {
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseSegment(segment: string, min: number, max: number, context: string): number[] {
  // Wildcard
  if (segment === "*") {
    return expandRange(min, max);
  }

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/", 2);
    const step = parseNumber(stepStr, 1, max - min, `${context} step`);

    let start: number;
    let end: number;

    if (base === "*") {
      start = min;
      end = max;
    } else if (base.includes("-")) {
      const [lo, hi] = base.split("-", 2);
      start = parseNumber(lo, min, max, `${context} range start`);
      end   = parseNumber(hi, min, max, `${context} range end`);
      if (start > end) {
        throw new RangeError(`${context}: range start ${start} > end ${end}`);
      }
    } else {
      start = parseNumber(base, min, max, `${context} step base`);
      end = max;
    }

    const values: number[] = [];
    for (let v = start; v <= end; v += step) {
      values.push(v);
    }
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-", 2);
    const start = parseNumber(lo, min, max, `${context} range start`);
    const end   = parseNumber(hi, min, max, `${context} range end`);
    if (start > end) {
      throw new RangeError(`${context}: range start ${start} > end ${end}`);
    }
    return expandRange(start, end);
  }

  // Single value
  return [parseNumber(segment, min, max, context)];
}

function parseField(field: string, min: number, max: number, context: string): number[] {
  const segments = field.split(",");
  const seen = new Set<number>();
  const values: number[] = [];

  for (const segment of segments) {
    const expanded = parseSegment(segment.trim(), min, max, context);
    for (const v of expanded) {
      if (!seen.has(v)) {
        seen.add(v);
        values.push(v);
      }
    }
  }

  return values.sort((a, b) => a - b);
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${parts.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;

  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronFields)[];
  const rawValues  = [minuteStr, hourStr, domStr, monthStr, dowStr];

  const result = {} as CronFields;

  for (let i = 0; i < fieldNames.length; i++) {
    const name    = fieldNames[i];
    const { min, max } = FIELD_RANGES[name];
    result[name]  = parseField(rawValues[i], min, max, name);
  }

  // Normalise dayOfWeek: treat 7 as Sunday (0) per POSIX convention
  if (result.dayOfWeek.includes(7)) {
    result.dayOfWeek = result.dayOfWeek.filter(v => v !== 7);
    if (!result.dayOfWeek.includes(0)) {
      result.dayOfWeek.unshift(0);
    }
    result.dayOfWeek.sort((a, b) => a - b);
  }

  return result;
}

export default parseCron;
export type { CronFields };

interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronFields;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

const FIELD_ORDER: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

function rangeArray(min: number, max: number): number[] {
  if (min > max) throw new Error(`Invalid range: ${min}-${max}`);
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function clamp(value: number, min: number, max: number, field: FieldName): number {
  if (value < min || value > max) {
    throw new Error(
      `Value ${value} out of range for field "${field}" (expected ${min}-${max})`
    );
  }
  return value;
}

function parseSegment(segment: string, field: FieldName): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step with wildcard: */n
  const stepWildcardMatch = segment.match(/^\*\/(\d+)$/);
  if (stepWildcardMatch) {
    const step = parseInt(stepWildcardMatch[1], 10);
    if (step <= 0) throw new Error(`Step value must be positive in field "${field}"`);
    const values: number[] = [];
    for (let i = min; i <= max; i += step) values.push(i);
    return values;
  }

  // Step with range: n-m/s
  const stepRangeMatch = segment.match(/^(\d+)-(\d+)\/(\d+)$/);
  if (stepRangeMatch) {
    const start = clamp(parseInt(stepRangeMatch[1], 10), min, max, field);
    const end = clamp(parseInt(stepRangeMatch[2], 10), min, max, field);
    const step = parseInt(stepRangeMatch[3], 10);
    if (step <= 0) throw new Error(`Step value must be positive in field "${field}"`);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Range: n-m
  const rangeMatch = segment.match(/^(\d+)-(\d+)$/);
  if (rangeMatch) {
    const start = clamp(parseInt(rangeMatch[1], 10), min, max, field);
    const end = clamp(parseInt(rangeMatch[2], 10), min, max, field);
    return rangeArray(start, end);
  }

  // Single number
  const numMatch = segment.match(/^(\d+)$/);
  if (numMatch) {
    return [clamp(parseInt(numMatch[1], 10), min, max, field)];
  }

  throw new Error(`Unrecognized cron segment "${segment}" in field "${field}"`);
}

function parseField(expression: string, field: FieldName): number[] {
  const parts = expression.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new Error(`Empty segment in field "${field}"`);
    for (const v of parseSegment(trimmed, field)) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new Error("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 fields in cron expression, got ${fields.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_ORDER.length; i++) {
    const fieldName = FIELD_ORDER[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

export default parseCron;

