interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronExpression;

const FIELD_META: Record<FieldName, { min: number; max: number; acceptedMax?: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6, acceptedMax: 7 }, // 7 = Sunday alias for 0
};

function buildRange(start: number, end: number): number[] {
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end}`);
  }
  const out: number[] = [];
  for (let i = start; i <= end; i++) out.push(i);
  return out;
}

function validateBounds(value: number, min: number, max: number, field: FieldName): void {
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}, ${max}] for field "${field}"`
    );
  }
}

function normalizeValues(values: number[], field: FieldName): number[] {
  const normalized = field === "dayOfWeek"
    ? values.map((v) => (v === 7 ? 0 : v))
    : values;
  return Array.from(new Set(normalized)).sort((a, b) => a - b);
}

function parseSingleToken(token: string, field: FieldName): number[] {
  const { min, max, acceptedMax = max } = FIELD_META[field];

  // Step: */n or start/n or start-end/n
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const base = token.slice(0, slashIdx);
    const stepRaw = token.slice(slashIdx + 1);
    const step = Number(stepRaw);

    if (!Number.isInteger(step) || step <= 0) {
      throw new TypeError(`Invalid step "${stepRaw}" in field "${field}"`);
    }

    let rangeStart: number;
    let rangeEnd: number;

    if (base === "*") {
      rangeStart = min;
      rangeEnd = max;
    } else if (base.includes("-")) {
      [rangeStart, rangeEnd] = parseDashRange(base, field);
    } else {
      rangeStart = parseIntStrict(base, field);
      validateBounds(rangeStart, min, acceptedMax, field);
      rangeEnd = max;
    }

    const out: number[] = [];
    for (let i = rangeStart; i <= rangeEnd; i += step) out.push(i);
    return out;
  }

  // Wildcard
  if (token === "*") {
    return buildRange(min, max);
  }

  // Range: start-end
  if (token.includes("-")) {
    const [start, end] = parseDashRange(token, field);
    return buildRange(start, end);
  }

  // Single integer
  const n = parseIntStrict(token, field);
  validateBounds(n, min, acceptedMax, field);
  return [n];
}

function parseDashRange(token: string, field: FieldName): [number, number] {
  const { min, max, acceptedMax = max } = FIELD_META[field];
  const parts = token.split("-");

  if (parts.length !== 2) {
    throw new SyntaxError(`Malformed range "${token}" in field "${field}"`);
  }

  const start = parseIntStrict(parts[0], field);
  const end = parseIntStrict(parts[1], field);

  validateBounds(start, min, acceptedMax, field);
  validateBounds(end, min, acceptedMax, field);

  if (start > end) {
    throw new RangeError(
      `Range start ${start} exceeds end ${end} in field "${field}"`
    );
  }

  return [start, end];
}

function parseIntStrict(raw: string, field: FieldName): number {
  const trimmed = raw.trim();
  if (!/^\d+$/.test(trimmed)) {
    throw new TypeError(`Non-numeric value "${raw}" in field "${field}"`);
  }
  return parseInt(trimmed, 10);
}

function parseField(raw: string, field: FieldName): number[] {
  if (!raw || raw.trim() === "") {
    throw new SyntaxError(`Empty value for field "${field}"`);
  }

  const tokens = raw.split(",");
  if (tokens.some((t) => t.trim() === "")) {
    throw new SyntaxError(`Trailing or double comma in field "${field}": "${raw}"`);
  }

  const collected: number[] = [];
  for (const token of tokens) {
    const values = parseSingleToken(token.trim(), field);
    collected.push(...values);
  }

  return normalizeValues(collected, field);
}

export function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}`
    );
  }

  const fieldNames: FieldName[] = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"];

  return Object.fromEntries(
    fieldNames.map((name, i) => [name, parseField(fields[i], name)])
  ) as CronExpression;
}

export default parseCron;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor({ maxTokens, refillRate, refillIntervalMs }: RateLimiterOptions) {
    if (maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.tokens = maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = intervalsNeeded * this.refillIntervalMs;

        setTimeout(attempt, Math.max(delay, 1));
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  return Array.from({ length: to - from + 1 }, (_, i) => i + from);
}

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter((v) => v >= min && v <= max);
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];
  const all = range(min, max);

  // comma list
  if (expr.includes(",")) {
    const vals = expr.split(",").flatMap((part) => parseField(part.trim(), field));
    return [...new Set(vals)].sort((a, b) => a - b);
  }

  // step: */n or a-b/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step in "${expr}"`);

    let base: number[];
    if (rangePart === "*") {
      base = all;
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range in "${expr}"`);
      base = clamp(range(lo, hi), min, max);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) throw new Error(`Invalid step start in "${expr}"`);
      base = clamp(range(start, max), min, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // wildcard
  if (expr === "*") return all;

  // range: a-b
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) throw new Error(`Invalid range "${expr}"`);
    const result = clamp(range(lo, hi), min, max);
    if (!result.length) throw new Error(`Range "${expr}" out of bounds for ${field}`);
    return result;
  }

  // literal number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid value "${expr}" for ${field}`);
  if (num < min || num > max) throw new Error(`Value ${num} out of range [${min},${max}] for ${field}`);
  return [num];
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) throw new Error(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute: { min: 0, max: 59 },
  hour: { min: 0, max: 23 },
  dayOfMonth: { min: 1, max: 31 },
  month: { min: 1, max: 12 },
  dayOfWeek: { min: 0, max: 6 },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangepart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }
    const start = rangepart === "*" ? min : parseInt(rangepart.split("-")[0], 10);
    const end = rangepart === "*" ? max : (rangepart.includes("-") ? parseInt(rangepart.split("-")[1], 10) : max);
    clamp(start, min, max);
    clamp(end, min, max);
    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new Error(`Invalid range: ${segment}`);
    }
    clamp(start, min, max);
    clamp(end, min, max);
    if (start > end) {
      throw new RangeError(`Range start ${start} is greater than end ${end}`);
    }
    const values: number[] = [];
    for (let i = start; i <= end; i++) {
      values.push(i);
    }
    return values;
  }

  // Single number
  const num = parseInt(segment, 10);
  if (isNaN(num)) {
    throw new Error(`Invalid cron field value: ${segment}`);
  }
  clamp(num, min, max);
  return [num];
}

function parseField(expression: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];
  const parts = expression.split(",");
  const valueSet = new Set<number>();

  for (const part of parts) {
    const values = parseSegment(part.trim(), min, max);
    for (const v of values) {
      valueSet.add(v);
    }
  }

  return Array.from(valueSet).sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] =
    fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in "${context}"`);
  }
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") {
    return range(min, max);
  }

  // Step: */n or start-end/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new RangeError(`Invalid step value "${stepStr}" in "${segment}"`);
    }

    let base: number[];
    if (rangePart === "*") {
      base = range(min, max);
    } else if (rangePart.includes("-")) {
      const [startStr, endStr] = rangePart.split("-");
      const start = parseInt(startStr, 10);
      const end = parseInt(endStr, 10);
      if (isNaN(start) || isNaN(end)) {
        throw new TypeError(`Invalid range "${rangePart}" in "${segment}"`);
      }
      assertInRange(start, min, max, segment);
      assertInRange(end, min, max, segment);
      base = range(start, end);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) {
        throw new TypeError(`Invalid step base "${rangePart}" in "${segment}"`);
      }
      assertInRange(start, min, max, segment);
      base = range(start, max);
    }

    return base.filter((_, i) => i % step === 0);
  }

  // Range: start-end
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new TypeError(`Invalid range "${segment}"`);
    }
    assertInRange(start, min, max, segment);
    assertInRange(end, min, max, segment);
    return range(start, end);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new TypeError(`Invalid value "${segment}" for field "${field}"`);
  }
  assertInRange(value, min, max, segment);
  return [value];
}

function parseField(expression: string, field: CronField): number[] {
  const segments = expression.split(",");
  if (segments.length === 0) {
    throw new TypeError(`Empty field expression for "${field}"`);
  }

  const values = new Set<number>();
  for (const segment of segments) {
    const parsed = parseSegment(segment.trim(), field);
    for (const v of parsed) values.add(v);
  }

  return Array.from(values).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string" || !expression.trim()) {
    throw new TypeError("Cron expression must be a non-empty string");
  }

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new TypeError(
      `Cron expression must have exactly 5 fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(dayOfMonthExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dayOfWeekExpr, "dayOfWeek"),
  };
}

export default parseCron;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

type FieldConfig = {
  min: number;
  max: number;
};

const FIELD_CONFIGS: FieldConfig[] = [
  { min: 0, max: 59 },  // minute
  { min: 0, max: 23 },  // hour
  { min: 1, max: 31 },  // dayOfMonth
  { min: 1, max: 12 },  // month
  { min: 0, max: 7 },   // dayOfWeek (0 and 7 both = Sunday)
];

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function validateInt(raw: string, min: number, max: number, context: string): number {
  const n = Number(raw);
  if (!Number.isInteger(n) || raw.trim() === "") {
    throw new Error(`${context}: "${raw}" not integer`);
  }
  if (n < min || n > max) {
    throw new Error(`${context}: ${n} out of range [${min},${max}]`);
  }
  return n;
}

function parseField(expr: string, cfg: FieldConfig, fieldName: string): number[] {
  const { min, max } = cfg;

  // Comma list — recurse on each segment
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some(p => p === "")) throw new Error(`${fieldName}: empty segment in list`);
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part, cfg, fieldName)) values.add(v);
    }
    return [...values].sort((a, b) => a - b);
  }

  // Step: */n  or  start-end/n  or  start/n
  if (expr.includes("/")) {
    const slashIdx = expr.indexOf("/");
    const stepRaw = expr.slice(slashIdx + 1);
    const step = validateInt(stepRaw, 1, max - min, `${fieldName} step`);
    const base = expr.slice(0, slashIdx);

    let rangeMin: number;
    let rangeMax: number;

    if (base === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (base.includes("-")) {
      const [lo, hi] = parseRange(base, cfg, fieldName);
      rangeMin = lo;
      rangeMax = hi;
    } else {
      rangeMin = validateInt(base, min, max, `${fieldName} step-start`);
      rangeMax = max;
    }

    const values: number[] = [];
    for (let v = rangeMin; v <= rangeMax; v += step) values.push(v);
    return values;
  }

  // Range: n-m
  if (expr.includes("-")) {
    const [lo, hi] = parseRange(expr, cfg, fieldName);
    const values: number[] = [];
    for (let v = lo; v <= hi; v++) values.push(v);
    return values;
  }

  // Wildcard
  if (expr === "*") {
    const values: number[] = [];
    for (let v = min; v <= max; v++) values.push(v);
    return values;
  }

  // Single number
  return [validateInt(expr, min, max, fieldName)];
}

function parseRange(expr: string, cfg: FieldConfig, fieldName: string): [number, number] {
  const idx = expr.indexOf("-");
  if (idx === 0) throw new Error(`${fieldName}: range missing low bound`);
  const loRaw = expr.slice(0, idx);
  const hiRaw = expr.slice(idx + 1);
  if (hiRaw === "") throw new Error(`${fieldName}: range missing high bound`);
  const lo = validateInt(loRaw, cfg.min, cfg.max, `${fieldName} range-lo`);
  const hi = validateInt(hiRaw, cfg.min, cfg.max, `${fieldName} range-hi`);
  if (lo > hi) throw new Error(`${fieldName}: range lo ${lo} > hi ${hi}`);
  return [lo, hi];
}

function normalizeDayOfWeek(values: number[]): number[] {
  // 0 and 7 both mean Sunday; normalize 7 → 0, deduplicate
  const normalized = new Set(values.map(v => (v === 7 ? 0 : v)));
  return [...normalized].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new Error("expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`expected 5 fields, got ${fields.length}`);
  }

  const parsed = fields.map((field, i) => parseField(field, FIELD_CONFIGS[i], FIELD_NAMES[i]));

  return {
    minute:     parsed[0],
    hour:       parsed[1],
    dayOfMonth: parsed[2],
    month:      parsed[3],
    dayOfWeek:  normalizeDayOfWeek(parsed[4]),
  };
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private scheduledCheck: ReturnType<typeof setTimeout> | null;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    const { maxTokens, refillRate, refillIntervalMs } = options;

    if (!Number.isFinite(maxTokens) || maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a positive finite number, got: ${maxTokens}`);
    }
    if (!Number.isFinite(refillRate) || refillRate < 0) {
      throw new RangeError(`refillRate must be a non-negative finite number, got: ${refillRate}`);
    }
    if (!Number.isFinite(refillIntervalMs) || refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a positive finite number, got: ${refillIntervalMs}`);
    }

    this.maxTokens = maxTokens;
    this.refillRate = refillRate;
    this.refillIntervalMs = refillIntervalMs;
    this.currentTokens = maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.scheduledCheck = null;
  }

  private applyRefill(): void {
    if (this.refillRate === 0) return;

    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed < this.refillIntervalMs) return;

    const intervals = Math.floor(elapsed / this.refillIntervalMs);
    const tokensToAdd = intervals * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime += intervals * this.refillIntervalMs;
  }

  private validateTokenArg(tokens: number, context: string): void {
    if (!Number.isFinite(tokens) || tokens <= 0) {
      throw new RangeError(`${context}: tokens must be a positive finite number, got: ${tokens}`);
    }
  }

  tryConsume(tokens: number = 1): boolean {
    this.validateTokenArg(tokens, 'tryConsume');

    // A request exceeding the bucket capacity can never succeed.
    if (tokens > this.maxTokens) return false;

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.applyRefill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    // Validate synchronously so callers can catch programming errors immediately.
    try {
      this.validateTokenArg(tokens, 'waitForTokens');
    } catch (err) {
      return Promise.reject(err);
    }

    // An amount exceeding the bucket's capacity would wait forever — reject early.
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `waitForTokens: requested ${tokens} tokens exceeds maxTokens ${this.maxTokens}; ` +
            `this promise would never resolve`
        )
      );
    }

    this.applyRefill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.ensureRefillCheck();
    });
  }

  private ensureRefillCheck(): void {
    // No point in scheduling if the bucket never refills on its own.
    if (this.scheduledCheck !== null || this.refillRate === 0) return;

    const elapsed = Date.now() - this.lastRefillTime;
    const delay = Math.max(0, this.refillIntervalMs - (elapsed % this.refillIntervalMs));

    this.scheduledCheck = setTimeout(() => {
      this.scheduledCheck = null;
      this.drainQueue();
    }, delay);
  }

  private drainQueue(): void {
    this.applyRefill();

    // Service waiters in FIFO order; stop at the first one that can't be satisfied
    // to prevent head-of-line starvation from being bypassed.
    while (this.waitQueue.length > 0) {
      const waiter = this.waitQueue[0]!;

      if (this.currentTokens < waiter.tokens) break;

      this.currentTokens -= waiter.tokens;
      this.waitQueue.shift();
      waiter.resolve();
    }

    if (this.waitQueue.length > 0) {
      this.ensureRefillCheck();
    }
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(from: number, to: number): number[] {
  if (from > to) throw new RangeError(`Invalid range: ${from}-${to}`);
  return Array.from({ length: to - from + 1 }, (_, i) => from + i);
}

function assertInRange(val: number, min: number, max: number, ctx: string): void {
  if (val < min || val > max)
    throw new RangeError(`${ctx}: value ${val} outside [${min},${max}]`);
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Wildcard
  if (segment === "*") return range(min, max);

  // Step: */n or a-b/n
  if (segment.includes("/")) {
    const [base, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`${field}: invalid step "${stepStr}"`);

    let from = min;
    let to = max;

    if (base !== "*") {
      if (base.includes("-")) {
        const [lo, hi] = base.split("-").map(Number);
        if (isNaN(lo) || isNaN(hi)) throw new RangeError(`${field}: invalid range "${base}"`);
        assertInRange(lo, min, max, field);
        assertInRange(hi, min, max, field);
        from = lo;
        to = hi;
      } else {
        const lo = parseInt(base, 10);
        if (isNaN(lo)) throw new RangeError(`${field}: invalid base "${base}"`);
        assertInRange(lo, min, max, field);
        from = lo;
      }
    }

    const result: number[] = [];
    for (let v = from; v <= to; v += step) result.push(v);
    return result;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    if (isNaN(lo) || isNaN(hi)) throw new RangeError(`${field}: invalid range "${segment}"`);
    assertInRange(lo, min, max, field);
    assertInRange(hi, min, max, field);
    return range(lo, hi);
  }

  // Single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new RangeError(`${field}: invalid value "${segment}"`);
  assertInRange(val, min, max, field);
  return [val];
}

function parseField(raw: string, field: CronField): number[] {
  if (!raw || raw.trim() === "")
    throw new RangeError(`${field}: empty field`);

  // Comma list — split and union, then sort+dedupe
  const segments = raw.split(",");
  const seen = new Set<number>();
  for (const seg of segments) {
    for (const v of parseSegment(seg.trim(), field)) seen.add(v);
  }
  return [...seen].sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string")
    throw new TypeError("expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new RangeError(`expected 5 fields, got ${fields.length}`);

  const [rawMinute, rawHour, rawDom, rawMonth, rawDow] = fields;

  return {
    minute: parseField(rawMinute, "minute"),
    hour: parseField(rawHour, "hour"),
    dayOfMonth: parseField(rawDom, "dayOfMonth"),
    month: parseField(rawMonth, "month"),
    dayOfWeek: parseField(rawDow, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const value = obj[key];
    const flatKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, flatKey, result);
    } else {
      result[flatKey] = Array.isArray(value) ? JSON.stringify(value) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = obj as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const value = obj[key];
    const newKey = prefix ? `${prefix}.${key}` : key;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value as object).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: Array<{ tokens: number; resolve: () => void }>;
  private pendingCheck: boolean;

  constructor(options: {
    maxTokens: number;
    refillRate: number;
    refillIntervalMs: number;
  }) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0)
      throw new RangeError("maxTokens must be a positive finite number");
    if (!Number.isFinite(options.refillRate) || options.refillRate <= 0)
      throw new RangeError("refillRate must be a positive finite number");
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0)
      throw new RangeError("refillIntervalMs must be a positive finite number");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.pendingCheck = false;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    if (elapsed > 0) {
      const added = (elapsed / this.refillIntervalMs) * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + added);
      this.lastRefillTime = now;
    }
  }

  private msUntilAvailable(needed: number): number {
    const deficit = needed - this.currentTokens;
    return Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
  }

  private scheduleCheck(): void {
    if (this.pendingCheck || this.waitQueue.length === 0) return;
    this.refill();

    const next = this.waitQueue[0];
    if (this.currentTokens >= next.tokens) {
      this.drainQueue();
      return;
    }

    this.pendingCheck = true;
    setTimeout(() => {
      this.pendingCheck = false;
      this.drainQueue();
    }, this.msUntilAvailable(next.tokens));
  }

  private drainQueue(): void {
    while (this.waitQueue.length > 0) {
      this.refill();
      const next = this.waitQueue[0];

      if (this.currentTokens >= next.tokens) {
        this.waitQueue.shift();
        this.currentTokens -= next.tokens;
        next.resolve();
      } else {
        if (!this.pendingCheck) {
          this.pendingCheck = true;
          setTimeout(() => {
            this.pendingCheck = false;
            this.drainQueue();
          }, this.msUntilAvailable(next.tokens));
        }
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0)
      throw new RangeError("tokens must be a non-negative finite number");
    if (tokens === 0) return true;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }
    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0)
      return Promise.reject(
        new RangeError("tokens must be a non-negative finite number")
      );
    if (tokens > this.maxTokens)
      return Promise.reject(
        new RangeError(
          `Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens}) — request can never be satisfied`
        )
      );
    if (tokens === 0) return Promise.resolve();
    if (this.tryConsume(tokens)) return Promise.resolve();

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      this.scheduleCheck();
    });
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = intervalsNeeded * this.refillIntervalMs;

        setTimeout(attempt, Math.max(delay, 1));
      };

      attempt();
    });
  }
}

export default RateLimiter;

interface RateLimiterOptions {
  maxTokens: number;
