class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceeds maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const elapsed = Date.now() - this.lastRefillTime;
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs - elapsed);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronField = {
  min: number;
  max: number;
};

const FIELDS: Record<string, CronField> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

export type CronResult = {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
};

function clamp(n: number, min: number, max: number): number {
  if (n < min || n > max) throw new RangeError(`Value ${n} out of range [${min}, ${max}]`);
  return n;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = field;

  // Step: */n or range/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) throw new Error(`Invalid step: ${stepStr}`);

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map(Number);
        start = clamp(lo, min, max);
        end   = clamp(hi, min, max);
        if (start > end) throw new RangeError(`Invalid range ${rangePart}`);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) values.push(i);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let i = min; i <= max; i++) values.push(i);
    return values;
  }

  // Range: n-m
  if (segment.includes("-")) {
    const [lo, hi] = segment.split("-").map(Number);
    const start = clamp(lo, min, max);
    const end   = clamp(hi, min, max);
    if (start > end) throw new RangeError(`Invalid range: ${segment}`);
    const values: number[] = [];
    for (let i = start; i <= end; i++) values.push(i);
    return values;
  }

  // List: n,m,o
  if (segment.includes(",")) {
    return segment.split(",").map(s => {
      const n = parseInt(s.trim(), 10);
      if (isNaN(n)) throw new Error(`Invalid value: ${s}`);
      return clamp(n, min, max);
    });
  }

  // Single number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid token: ${segment}`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");

  const parts = expression.trim().split(/\s+/);
  if (parts.length !== 5) throw new Error(`Expected 5 fields, got ${parts.length}`);

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = parts;

  return {
    minute:     parseSegment(minuteStr, FIELDS.minute),
    hour:       parseSegment(hourStr,   FIELDS.hour),
    dayOfMonth: parseSegment(domStr,    FIELDS.dayOfMonth),
    month:      parseSegment(monthStr,  FIELDS.month),
    dayOfWeek:  parseSegment(dowStr,    FIELDS.dayOfWeek),
  };
}

export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldConfig = {
  readonly name: string;
  readonly min: number;
  readonly max: number;
};

const FIELD_CONFIGS = [
  { name: "minute",     min: 0, max: 59 },
  { name: "hour",       min: 0, max: 23 },
  { name: "dayOfMonth", min: 1, max: 31 },
  { name: "month",      min: 1, max: 12 },
  { name: "dayOfWeek",  min: 0, max:  6 },
] as const satisfies FieldConfig[];

function parseInteger(raw: string, fieldName: string): number {
  if (!/^\d+$/.test(raw)) {
    throw new Error(`Field "${fieldName}": "${raw}" is not a valid non-negative integer`);
  }
  return Number(raw);
}

function assertInRange(value: number, min: number, max: number, fieldName: string, context: string): void {
  if (value < min || value > max) {
    throw new Error(
      `Field "${fieldName}": value ${value} (from "${context}") is outside valid range [${min}, ${max}]`
    );
  }
}

function expandStep(rangeMin: number, rangeMax: number, step: number): number[] {
  if (step <= 0) throw new Error(`Step must be a positive integer, got ${step}`);
  const values: number[] = [];
  for (let v = rangeMin; v <= rangeMax; v += step) values.push(v);
  return values;
}

function parseSegment(segment: string, config: FieldConfig): number[] {
  const { name, min, max } = config;

  // Step expression: */n or start-end/n or start/n
  if (segment.includes("/")) {
    const slashParts = segment.split("/");
    if (slashParts.length !== 2) {
      throw new Error(`Field "${name}": "${segment}" contains multiple "/" characters`);
    }
    const [rangePart, stepRaw] = slashParts;
    const step = parseInteger(stepRaw, name);
    if (step === 0) {
      throw new Error(`Field "${name}": step value must be >= 1`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (rangePart === "*") {
      rangeMin = min;
      rangeMax = max;
    } else if (rangePart.includes("-")) {
      const dashParts = rangePart.split("-");
      if (dashParts.length !== 2) {
        throw new Error(`Field "${name}": "${rangePart}" is not a valid range`);
      }
      rangeMin = parseInteger(dashParts[0], name);
      rangeMax = parseInteger(dashParts[1], name);
      assertInRange(rangeMin, min, max, name, segment);
      assertInRange(rangeMax, min, max, name, segment);
      if (rangeMin > rangeMax) {
        throw new Error(`Field "${name}": range start ${rangeMin} exceeds end ${rangeMax} in "${segment}"`);
      }
    } else {
      // e.g. "2/15" — start from 2, step through max
      rangeMin = parseInteger(rangePart, name);
      assertInRange(rangeMin, min, max, name, segment);
      rangeMax = max;
    }

    return expandStep(rangeMin, rangeMax, step);
  }

  // Range expression: start-end
  if (segment.includes("-")) {
    const dashParts = segment.split("-");
    if (dashParts.length !== 2) {
      throw new Error(`Field "${name}": "${segment}" is not a valid range`);
    }
    const start = parseInteger(dashParts[0], name);
    const end   = parseInteger(dashParts[1], name);
    assertInRange(start, min, max, name, segment);
    assertInRange(end,   min, max, name, segment);
    if (start > end) {
      throw new Error(`Field "${name}": range start ${start} exceeds end ${end} in "${segment}"`);
    }
    const values: number[] = [];
    for (let v = start; v <= end; v++) values.push(v);
    return values;
  }

  // Wildcard
  if (segment === "*") {
    const values: number[] = [];
    for (let v = min; v <= max; v++) values.push(v);
    return values;
  }

  // Single integer
  const value = parseInteger(segment, name);
  assertInRange(value, min, max, name, segment);
  return [value];
}

function parseField(field: string, config: FieldConfig): number[] {
  if (!field || field.trim() === "") {
    throw new Error(`Field "${config.name}" is empty`);
  }

  // Comma-separated list — each element may itself be a segment
  const segments = field.split(",");
  if (segments.length > 1) {
    const seen = new Set<number>();
    for (const segment of segments) {
      const trimmed = segment.trim();
      if (!trimmed) {
        throw new Error(`Field "${config.name}": empty element in list "${field}"`);
      }
      for (const v of parseSegment(trimmed, config)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(field.trim(), config);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const trimmed = expression.trim();
  if (!trimmed) {
    throw new Error("Cron expression must not be empty");
  }

  const fields = trimmed.split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  return {
    minute:     parseField(fields[0], FIELD_CONFIGS[0]),
    hour:       parseField(fields[1], FIELD_CONFIGS[1]),
    dayOfMonth: parseField(fields[2], FIELD_CONFIGS[2]),
    month:      parseField(fields[3], FIELD_CONFIGS[3]),
    dayOfWeek:  parseField(fields[4], FIELD_CONFIGS[4]),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined) return result;

  for (const key of Object.keys(obj)) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    // Reject prototype pollution vectors
    if (key === "__proto__" || key === "constructor" || key === "prototype") {
      continue;
    }

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val as object).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = val as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  min: number;
  max: number;
};

const FIELD_RANGES: Record<string, CronField> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

export type CronResult = {
  minute:     number[];
  hour:       number[];
  dayOfMonth: number[];
  month:      number[];
  dayOfWeek:  number[];
};

function clamp(values: number[], min: number, max: number): number[] {
  return values.filter(v => v >= min && v <= max);
}

function range(start: number, end: number): number[] {
  if (start > end) throw new Error(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = field;

  // Step: */N or start-end/N
  if (segment.includes('/')) {
    const [left, stepStr] = segment.split('/');
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    const base = left === '*'
      ? range(min, max)
      : left.includes('-')
        ? (() => { const [s, e] = left.split('-').map(Number); return range(s, e); })()
        : [parseInt(left, 10)];

    return clamp(base.filter((_, i) => i % step === 0), min, max);
  }

  // Range: N-M
  if (segment.includes('-')) {
    const [s, e] = segment.split('-').map(Number);
    if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range: ${segment}`);
    return clamp(range(s, e), min, max);
  }

  // Wildcard
  if (segment === '*') {
    return range(min, max);
  }

  // Number
  const n = parseInt(segment, 10);
  if (isNaN(n)) throw new Error(`Invalid value: ${segment}`);
  const result = clamp([n], min, max);
  if (result.length === 0) throw new Error(`Value ${n} out of range [${min}, ${max}]`);
  return result;
}

function parseField(expr: string, field: CronField): number[] {
  const parts = expr.split(',');
  const values = new Set<number>();
  for (const part of parts) {
    for (const v of parseSegment(part.trim(), field)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, FIELD_RANGES.minute),
    hour:       parseField(hourExpr,   FIELD_RANGES.hour),
    dayOfMonth: parseField(domExpr,    FIELD_RANGES.dayOfMonth),
    month:      parseField(monthExpr,  FIELD_RANGES.month),
    dayOfWeek:  parseField(dowExpr,    FIELD_RANGES.dayOfWeek),
  };
}

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

type FieldName = keyof CronResult;

const FIELD_RANGES: Record<FieldName, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`Value ${value} out of valid range [${min}, ${max}] in "${context}"`);
  }
}

function parseToken(token: string, min: number, max: number): number[] {
  // Step expression: base/step (e.g. "*/15", "1-30/2", "5/10")
  if (token.includes('/')) {
    const slashCount = (token.match(/\//g) ?? []).length;
    if (slashCount !== 1) {
      throw new SyntaxError(`Invalid step expression: "${token}"`);
    }

    const [baseStr, stepStr] = token.split('/');
    const step = parseInt(stepStr, 10);

    if (!Number.isInteger(step) || isNaN(step) || step <= 0) {
      throw new RangeError(`Step must be a positive integer in "${token}"`);
    }

    let rangeMin: number;
    let rangeMax: number;

    if (baseStr === '*') {
      rangeMin = min;
      rangeMax = max;
    } else if (baseStr.includes('-')) {
      [rangeMin, rangeMax] = parseRangeBounds(baseStr, min, max);
    } else {
      rangeMin = parseInt(baseStr, 10);
      if (isNaN(rangeMin)) {
        throw new SyntaxError(`Invalid step base in "${token}"`);
      }
      assertInRange(rangeMin, min, max, token);
      rangeMax = max;
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Wildcard
  if (token === '*') {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Range expression: n-m
  if (token.includes('-')) {
    const [rangeMin, rangeMax] = parseRangeBounds(token, min, max);
    return Array.from({ length: rangeMax - rangeMin + 1 }, (_, i) => i + rangeMin);
  }

  // Single number
  const num = parseInt(token, 10);
  if (isNaN(num) || token.trim() !== String(num)) {
    throw new SyntaxError(`Invalid cron token: "${token}"`);
  }
  assertInRange(num, min, max, token);
  return [num];
}

function parseRangeBounds(token: string, min: number, max: number): [number, number] {
  const parts = token.split('-');
  if (parts.length !== 2) {
    throw new SyntaxError(`Invalid range expression: "${token}"`);
  }

  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);

  if (isNaN(start) || isNaN(end)) {
    throw new SyntaxError(`Non-numeric bounds in range: "${token}"`);
  }
  if (start > end) {
    throw new RangeError(`Range start ${start} exceeds end ${end} in "${token}"`);
  }

  assertInRange(start, min, max, token);
  assertInRange(end, min, max, token);

  return [start, end];
}

function parseField(field: string, min: number, max: number): number[] {
  if (!field || field.trim() === '') {
    throw new SyntaxError('Empty cron field');
  }

  // Comma-separated list — handled first, each part parsed independently
  if (field.includes(',')) {
    const seen = new Set<number>();
    for (const part of field.split(',')) {
      const trimmed = part.trim();
      if (!trimmed) {
        throw new SyntaxError(`Empty element in comma list: "${field}"`);
      }
      for (const v of parseToken(trimmed, min, max)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseToken(field.trim(), min, max);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== 'string' || expression.trim() === '') {
    throw new TypeError('Cron expression must be a non-empty string');
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields; got ${fields.length}: "${expression}"`
    );
  }

  const [minuteStr, hourStr, domStr, monthStr, dowStr] = fields;

  return {
    minute:     parseField(minuteStr, FIELD_RANGES.minute.min,     FIELD_RANGES.minute.max),
    hour:       parseField(hourStr,   FIELD_RANGES.hour.min,       FIELD_RANGES.hour.max),
    dayOfMonth: parseField(domStr,    FIELD_RANGES.dayOfMonth.min, FIELD_RANGES.dayOfMonth.max),
    month:      parseField(monthStr,  FIELD_RANGES.month.min,      FIELD_RANGES.month.max),
    dayOfWeek:  parseField(dowStr,    FIELD_RANGES.dayOfWeek.min,  FIELD_RANGES.dayOfWeek.max),
  };
}

type CronObject = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronObject, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0, 6],
};

function expandRange(min: number, max: number): number[] {
  if (min > max) throw new RangeError(`Invalid range: ${min}-${max}`);
  return Array.from({ length: max - min + 1 }, (_, i) => min + i);
}

function parseField(field: string, key: keyof CronObject): number[] {
  const [min, max] = FIELD_RANGES[key];

  const validate = (n: number): number => {
    if (!Number.isInteger(n) || n < min || n > max) {
      throw new RangeError(`Value ${n} out of range [${min},${max}] for field '${key}'`);
    }
    return n;
  };

  // Comma-separated list — recurse on each segment, flatten, deduplicate, sort
  if (field.includes(",")) {
    const values = field
      .split(",")
      .flatMap((segment) => parseField(segment.trim(), key));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Wildcard
  if (field === "*") return expandRange(min, max);

  // Step: */step or start-end/step
  if (field.includes("/")) {
    const [rangePart, stepStr] = field.split("/");
    const step = parseInt(stepStr, 10);
    if (!Number.isInteger(step) || step < 1) {
      throw new RangeError(`Invalid step value: ${stepStr}`);
    }
    let base: number[];
    if (rangePart === "*") {
      base = expandRange(min, max);
    } else if (rangePart.includes("-")) {
      const [lo, hi] = rangePart.split("-").map(Number);
      validate(lo); validate(hi);
      base = expandRange(lo, hi);
    } else {
      const start = validate(parseInt(rangePart, 10));
      base = expandRange(start, max);
    }
    return base.filter((_, i) => i % step === 0);
  }

  // Range: start-end
  if (field.includes("-")) {
    const [lo, hi] = field.split("-").map(Number);
    validate(lo); validate(hi);
    return expandRange(lo, hi);
  }

  // Single number
  const n = parseInt(field, 10);
  if (isNaN(n)) throw new SyntaxError(`Unparseable cron token: '${field}'`);
  return [validate(n)];
}

function parseCron(expression: string): CronObject {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const parts = expression.trim().split(/\s+/);

  if (parts.length !== 5) {
    throw new SyntaxError(
      `Expected 5 fields, got ${parts.length}: '${expression}'`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = parts;

  return {
    minute:     parseField(minuteRaw, "minute"),
    hour:       parseField(hourRaw,   "hour"),
    dayOfMonth: parseField(domRaw,    "dayOfMonth"),
    month:      parseField(monthRaw,  "month"),
    dayOfWeek:  parseField(dowRaw,    "dayOfWeek"),
  };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? (val as unknown as Primitive) : (val as Primitive);
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function clamp(value: number, min: number, max: number): number {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} is out of range [${min}, ${max}]`);
  }
  return value;
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step value: */n or a-b/n
  if (segment.includes("/")) {
    const [rangePart, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step <= 0) {
      throw new Error(`Invalid step value: ${stepStr}`);
    }

    let rangeMin = min;
    let rangeMax = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [startStr, endStr] = rangePart.split("-");
        rangeMin = clamp(parseInt(startStr, 10), min, max);
        rangeMax = clamp(parseInt(endStr, 10), min, max);
        if (rangeMin > rangeMax) {
          throw new RangeError(`Invalid range: ${rangePart}`);
        }
      } else {
        rangeMin = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const values: number[] = [];
    for (let i = rangeMin; i <= rangeMax; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: a-b
  if (segment.includes("-")) {
    const [startStr, endStr] = segment.split("-");
    const start = clamp(parseInt(startStr, 10), min, max);
    const end   = clamp(parseInt(endStr,   10), min, max);

    if (start > end) {
      throw new RangeError(`Invalid range: ${segment}`);
    }

    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // Wildcard
  if (segment === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // Single number
  const value = parseInt(segment, 10);
  if (isNaN(value)) {
    throw new Error(`Invalid cron segment: ${segment}`);
  }

  return [clamp(value, min, max)];
}

function parseField(field: string, min: number, max: number): number[] {
  // Comma-separated list
  const parts = field.split(",");
  const result = new Set<number>();

  for (const part of parts) {
    const values = parseSegment(part.trim(), min, max);
    for (const v of values) {
      // Normalize dayOfWeek: treat 7 as Sunday (0)
      result.add(v);
    }
  }

  return Array.from(result).sort((a, b) => a - b);
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Invalid cron expression: expected 5 fields, got ${fields.length}`
    );
  }

  const [minuteField, hourField, domField, monthField, dowField] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];

  const [minute, hour, dayOfMonth, month, dayOfWeek] = fieldNames.map(
    (name, i) => {
      const { min, max } = FIELD_RANGES[name];
      return parseField(fields[i], min, max);
    }
  );

  // Normalize dayOfWeek: treat 7 as Sunday (0)
  const normalizedDayOfWeek = Array.from(
    new Set(dayOfWeek.map((d) => (d === 7 ? 0 : d)))
  ).sort((a, b) => a - b);

  return { minute, hour, dayOfMonth, month, dayOfWeek: normalizedDayOfWeek };
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of valid range [${min}, ${max}] in "${context}"`
    );
  }
}

function expandRange(start: number, end: number, step: number): number[] {
  if (step <= 0) throw new RangeError(`Step must be a positive integer, got ${step}`);
  if (start > end) throw new RangeError(`Range start ${start} exceeds end ${end}`);
  const values: number[] = [];
  for (let i = start; i <= end; i += step) {
    values.push(i);
  }
  return values;
}

function parseSegment(token: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Step: */n  |  n/n  |  n-m/n
  if (token.includes("/")) {
    const slashIdx = token.indexOf("/");
    const rangePart = token.slice(0, slashIdx);
    const stepPart  = token.slice(slashIdx + 1);

    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0 || stepPart.trim() !== String(step)) {
      throw new SyntaxError(`Invalid step "${stepPart}" in token "${token}"`);
    }

    if (rangePart === "*") {
      return expandRange(min, max, step);
    }

    if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      assertInRange(s, min, max, token);
      assertInRange(e, min, max, token);
      return expandRange(s, e, step);
    }

    // bare number/step: treat start = number, end = max
    const start = parseInt(rangePart, 10);
    if (isNaN(start)) throw new SyntaxError(`Invalid token "${token}"`);
    assertInRange(start, min, max, token);
    return expandRange(start, max, step);
  }

  // Wildcard
  if (token === "*") {
    return expandRange(min, max, 1);
  }

  // Range: n-m
  if (token.includes("-")) {
    const parts = token.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Invalid range "${token}"`);
    const [s, e] = parts.map(Number);
    if (isNaN(s) || isNaN(e)) throw new SyntaxError(`Non-numeric range "${token}"`);
    assertInRange(s, min, max, token);
    assertInRange(e, min, max, token);
    return expandRange(s, e, 1);
  }

  // Single value
  const value = parseInt(token, 10);
  if (isNaN(value) || token.trim() !== String(value)) {
    throw new SyntaxError(`Invalid value "${token}" for field "${field}"`);
  }
  assertInRange(value, min, max, token);
  return [value];
}

function parseField(raw: string, field: CronField): number[] {
  if (typeof raw !== "string" || raw.trim() === "") {
    throw new SyntaxError(`Empty or invalid token for field "${field}"`);
  }

  // Comma-separated list — parsed recursively, each segment is a valid sub-expression
  const segments = raw.split(",");
  if (segments.length > 1) {
    const seen = new Set<number>();
    for (const seg of segments) {
      if (seg === "") throw new SyntaxError(`Trailing or double comma in "${raw}"`);
      for (const v of parseSegment(seg, field)) {
        seen.add(v);
      }
    }
    return Array.from(seen).sort((a, b) => a - b);
  }

  return parseSegment(raw, field);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== "string") {
    throw new TypeError(`parseCron expects a string, received ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Invalid cron expression: expected exactly 5 space-separated fields, got ${fields.length}`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;

  return {
    minute:     parseField(minuteRaw, "minute"),
    hour:       parseField(hourRaw,   "hour"),
    dayOfMonth: parseField(domRaw,    "dayOfMonth"),
    month:      parseField(monthRaw,  "month"),
    dayOfWeek:  parseField(dowRaw,    "dayOfWeek"),
  };
}

export class RateLimiter {
  private maxTokens: number;
  private refillRate: number;
  private refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: { maxTokens: number; refillRate: number; refillIntervalMs: number }) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.currentTokens = Math.min(
        this.maxTokens,
        this.currentTokens + intervals * this.refillRate
      );
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) throw new RangeError("tokens exceeds maxTokens capacity");

    while (!this.tryConsume(tokens)) {
      this.refill();
      const deficit = tokens - this.currentTokens;
      const intervalsNeeded = Math.ceil(deficit / this.refillRate);
      const waitMs = Math.max(1, intervalsNeeded * this.refillIntervalMs);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }
}

export default RateLimiter;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  }
  return val;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // Comma list — recurse on each part, flatten, deduplicate, sort
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some((p) => p.trim() === ""))
      throw new SyntaxError(`Empty segment in list: "${expr}"`);
    const vals = parts.flatMap((p) => parseField(p.trim(), field));
    return [...new Set(vals)].sort((a, b) => a - b);
  }

  // Step: */n  or  a-b/n
  if (expr.includes("/")) {
    const [rangeExpr, stepStr] = expr.split("/");
    if (!stepStr || stepStr.includes("/"))
      throw new SyntaxError(`Bad step expression: "${expr}"`);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`Step must be >= 1, got "${stepStr}"`);

    let start: number;
    let end: number;

    if (rangeExpr === "*") {
      start = min;
      end = max;
    } else if (rangeExpr.includes("-")) {
      [start, end] = parseRange(rangeExpr, min, max);
    } else {
      start = clamp(parseInt(rangeExpr, 10), min, max);
      end = max;
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // Wildcard
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Range: a-b
  if (expr.includes("-")) {
    const [start, end] = parseRange(expr, min, max);
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new SyntaxError(`Not a number: "${expr}"`);
  return [clamp(num, min, max)];
}

function parseRange(expr: string, min: number, max: number): [number, number] {
  const parts = expr.split("-");
  if (parts.length !== 2)
    throw new SyntaxError(`Bad range: "${expr}"`);
  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end))
    throw new SyntaxError(`Non-numeric range: "${expr}"`);
  clamp(start, min, max);
  clamp(end, min, max);
  if (start > end)
    throw new RangeError(`Range start ${start} > end ${end}`);
  return [start, end];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string")
    throw new TypeError("Cron expression must be a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(
      `Expected 5 fields, got ${fields.length}: "${expression}"`
    );

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined | bigint | symbol;
type NestedObject = { [key: string]: unknown };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  input: unknown,
  prefix = "",
  seen = new WeakSet<object>(),
  result: FlatObject = {}
): FlatObject {
  if (input === null || input === undefined) {
    if (prefix !== "") result[prefix] = input as Primitive;
    return result;
  }

  if (typeof input !== "object" && typeof input !== "function") {
    if (prefix !== "") result[prefix] = input as Primitive;
    return result;
  }

  if (typeof input === "function") {
    return result;
  }

  if (seen.has(input as object)) {
    throw new TypeError(
      `Circular reference detected at key: "${prefix}"`
    );
  }

  seen.add(input as object);

  const entries = Object.entries(input as NestedObject);

  if (entries.length === 0) {
    if (prefix !== "") result[prefix] = {} as unknown as Primitive;
    seen.delete(input as object);
    return result;
  }

  for (const [rawKey, value] of entries) {
    const key = String(rawKey);

    if (
      key === "__proto__" ||
      key === "constructor" ||
      key === "prototype"
    ) {
      continue;
    }

    const nextPrefix = prefix === "" ? key : `${prefix}.${key}`;

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      !(value instanceof Date) &&
      !(value instanceof RegExp) &&
      !(value instanceof Map) &&
      !(value instanceof Set)
    ) {
      flattenObject(value, nextPrefix, seen, result);
    } else if (Array.isArray(value)) {
      flattenObject(
        Object.fromEntries(value.map((v, i) => [String(i), v])),
        nextPrefix,
        seen,
        result
      );
    } else if (
      value instanceof Date ||
      value instanceof RegExp ||
      value instanceof Map ||
      value instanceof Set
    ) {
      result[nextPrefix] = String(value) as Primitive;
    } else if (typeof value === "function") {
      // skip functions at leaf level too
    } else {
      result[nextPrefix] = value as Primitive;
    }
  }

  seen.delete(input as object);
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive | Array<unknown> };

function flattenObject(
