interface CronFields {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<keyof CronFields, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

const FIELD_NAMES = Object.keys(FIELD_RANGES) as (keyof CronFields)[];

function range(start: number, end: number): number[] {
  const result: number[] = [];
  for (let i = start; i <= end; i++) result.push(i);
  return result;
}

function clamp(values: number[], min: number, max: number): number[] {
  return [...new Set(values.filter((v) => v >= min && v <= max))].sort(
    (a, b) => a - b
  );
}

function parseField(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const allValues = range(min, max);

  // Handle comma-separated list
  if (token.includes(",")) {
    const parts = token.split(",");
    const values = parts.flatMap((part) => parseField(part, min, max, fieldName));
    const result = clamp(values, min, max);
    if (result.length === 0) {
      throw new Error(
        `Invalid list value "${token}" for field "${fieldName}"`
      );
    }
    return result;
  }

  // Handle step values (e.g., */15, 1-30/5, 0/15)
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/", 2);
    const step = parseInt(stepPart, 10);
    if (isNaN(step) || step <= 0) {
      throw new Error(
        `Invalid step value "${stepPart}" in "${token}" for field "${fieldName}"`
      );
    }

    let base: number[];
    if (rangePart === "*") {
      base = allValues;
    } else if (rangePart.includes("-")) {
      base = parseRange(rangePart, min, max, fieldName);
    } else {
      const start = parseInt(rangePart, 10);
      if (isNaN(start)) {
        throw new Error(
          `Invalid start value "${rangePart}" in "${token}" for field "${fieldName}"`
        );
      }
      base = range(start, max);
    }

    const stepped = base.filter((v) => (v - base[0]) % step === 0);
    const result = clamp(stepped, min, max);
    if (result.length === 0) {
      throw new Error(
        `Step expression "${token}" produced no valid values for field "${fieldName}"`
      );
    }
    return result;
  }

  // Handle range (e.g., 1-5)
  if (token.includes("-")) {
    return parseRange(token, min, max, fieldName);
  }

  // Handle wildcard
  if (token === "*") {
    return allValues;
  }

  // Handle single number
  const num = parseInt(token, 10);
  if (isNaN(num)) {
    throw new Error(
      `Invalid value "${token}" for field "${fieldName}"`
    );
  }
  if (num < min || num > max) {
    throw new Error(
      `Value ${num} out of range [${min}, ${max}] for field "${fieldName}"`
    );
  }
  return [num];
}

function parseRange(
  token: string,
  min: number,
  max: number,
  fieldName: string
): number[] {
  const parts = token.split("-", 2);
  if (parts.length !== 2) {
    throw new Error(
      `Invalid range "${token}" for field "${fieldName}"`
    );
  }
  const start = parseInt(parts[0], 10);
  const end = parseInt(parts[1], 10);
  if (isNaN(start) || isNaN(end)) {
    throw new Error(
      `Invalid range values "${token}" for field "${fieldName}"`
    );
  }
  if (start > end) {
    throw new Error(
      `Range start ${start} is greater than end ${end} for field "${fieldName}"`
    );
  }
  const result = clamp(range(start, end), min, max);
  if (result.length === 0) {
    throw new Error(
      `Range "${token}" is entirely outside valid bounds [${min}, ${max}] for field "${fieldName}"`
    );
  }
  return result;
}

function parseCron(expression: string): CronFields {
  if (typeof expression !== "string") {
    throw new Error("Cron expression must be a string");
  }

  const tokens = expression.trim().split(/\s+/);
  if (tokens.length !== 5) {
    throw new Error(
      `Expected 5 fields, got ${tokens.length}: "${expression}"`
    );
  }

  const result = {} as CronFields;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const fieldName = FIELD_NAMES[i];
    const [min, max] = FIELD_RANGES[fieldName];
    result[fieldName] = parseField(tokens[i], min, max, fieldName);
  }

  return result;
}

