export interface CronExpression {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

interface FieldRange {
  min: number;
  max: number;
}

const FIELD_RANGES: Record<keyof CronExpression, FieldRange> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 6  },
};

function buildRange(start: number, end: number, step: number): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  if (start > end) throw new Error(`Range start ${start} > end ${end}`);
  const result: number[] = [];
  for (let i = start; i <= end; i += step) {
    result.push(i);
  }
  return result;
}

function assertInBounds(value: number, min: number, max: number, context: string): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(`${context}: value ${value} is out of allowed range [${min}, ${max}]`);
  }
}

function parseSegment(segment: string, min: number, max: number): number[] {
  // Step expression: */n or n-m/n or n/n
  if (segment.includes('/')) {
    const slashIdx = segment.lastIndexOf('/');
    const rangePart = segment.slice(0, slashIdx);
    const stepStr = segment.slice(slashIdx + 1);
    const step = parseInt(stepStr, 10);

    if (isNaN(step) || step < 1) {
      throw new Error(`Invalid step value: "${stepStr}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === '*') {
      start = min;
      end = max;
    } else if (rangePart.includes('-')) {
      const dashIdx = rangePart.indexOf('-');
      const s = parseInt(rangePart.slice(0, dashIdx), 10);
      const e = parseInt(rangePart.slice(dashIdx + 1), 10);
      if (isNaN(s) || isNaN(e)) throw new Error(`Invalid range in step expression: "${rangePart}"`);
      assertInBounds(s, min, max, `Range start "${s}"`);
      assertInBounds(e, min, max, `Range end "${e}"`);
      start = s;
      end = e;
    } else {
      const base = parseInt(rangePart, 10);
      if (isNaN(base)) throw new Error(`Invalid base in step expression: "${rangePart}"`);
      assertInBounds(base, min, max, `Step base "${base}"`);
      start = base;
      end = max;
    }

    return buildRange(start, end, step);
  }

  // Wildcard
  if (segment === '*') {
    return buildRange(min, max, 1);
  }

  // Range: n-m
  if (segment.includes('-')) {
    const dashIdx = segment.indexOf('-');
    const startStr = segment.slice(0, dashIdx);
    const endStr = segment.slice(dashIdx + 1);
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);

    if (isNaN(start) || isNaN(end)) throw new Error(`Invalid range: "${segment}"`);
    assertInBounds(start, min, max, `Range start`);
    assertInBounds(end, min, max, `Range end`);

    return buildRange(start, end, 1);
  }

  // Plain integer
  const value = parseInt(segment, 10);
  if (isNaN(value) || segment.trim() === '') {
    throw new Error(`Invalid cron field value: "${segment}"`);
  }
  assertInBounds(value, min, max, `Value`);
  return [value];
}

function parseField(field: string, min: number, max: number): number[] {
  if (!field || field.trim() === '') {
    throw new Error('Empty cron field is not allowed');
  }

  const parts = field.split(',');
  const seen = new Set<number>();

  for (const part of parts) {
    const trimmed = part.trim();
    if (trimmed === '') throw new Error(`Empty segment in comma-separated field: "${field}"`);
    for (const v of parseSegment(trimmed, min, max)) {
      seen.add(v);
    }
  }

  return Array.from(seen).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronExpression {
  if (typeof expression !== 'string') {
    throw new TypeError(`parseCron expects a string, got ${typeof expression}`);
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Cron expression must have exactly 5 fields (minute hour dayOfMonth month dayOfWeek), got ${fields.length}: "${expression}"`
    );
  }

  const [minuteRaw, hourRaw, domRaw, monthRaw, dowRaw] = fields;
  const r = FIELD_RANGES;

  return {
    minute:     parseField(minuteRaw, r.minute.min,     r.minute.max),
    hour:       parseField(hourRaw,   r.hour.min,       r.hour.max),
