      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value) &&
      Object.keys(value).length > 0
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value) ? (JSON.stringify(value) as Primitive) : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const added = intervals * this.refillRate;
      this.tokens = Math.min(this.maxTokens, this.tokens + added);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens — will never be satisfiable"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const delay = Math.max(1, intervalsNeeded * this.refillIntervalMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;

type PlainObject = Record<string, unknown>;

const isPlainObject = (value: unknown): value is PlainObject =>
  value !== null &&
  typeof value === "object" &&
  !Array.isArray(value) &&
  !(value instanceof Date) &&
  !(value instanceof RegExp) &&
  !(value instanceof Map) &&
  !(value instanceof Set);

const flatten = (
  obj: PlainObject,
  prefix: string,
  seen: WeakSet<PlainObject>,
  result: PlainObject,
): void => {
  if (seen.has(obj)) {
    if (prefix) result[prefix] = "[Circular]";
    return;
  }

  seen.add(obj);

  const entries = Object.entries(obj);

  if (entries.length === 0) {
    if (prefix) result[prefix] = obj;
    seen.delete(obj);
    return;
  }

  for (const [key, value] of entries) {
    const dotKey = prefix ? `${prefix}.${key}` : key;

    if (isPlainObject(value)) {
      flatten(value, dotKey, seen, result);
    } else {
      result[dotKey] = value;
    }
  }

  seen.delete(obj);
};

const flattenObject = (obj: PlainObject): PlainObject => {
  if (!isPlainObject(obj)) {
    throw new TypeError(`Expected a plain object, got ${obj === null ? "null" : typeof obj}`);
  }

  const result: PlainObject = {};
  flatten(obj, "", new WeakSet(), result);
  return result;
};

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function assertRange(value: number, min: number, max: number, field: CronField): void {
  if (!Number.isInteger(value) || value < min || value > max) {
    throw new RangeError(
      `Field "${field}": value ${value} out of range [${min}, ${max}]`
    );
  }
}

function expand(min: number, max: number, step: number): number[] {
  const out: number[] = [];
  for (let i = min; i <= max; i += step) out.push(i);
  return out;
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // step on wildcard: */N
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    if (step < 1) throw new RangeError(`Field "${field}": step must be >= 1`);
    return expand(min, max, step);
  }

  // wildcard
  if (segment === "*") return expand(min, max, 1);

  // range with optional step: N-M or N-M/S
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const [rangePart, stepPart] = segment.split("/");
    const [lo, hi] = rangePart.split("-").map(Number);
    const step = stepPart ? parseInt(stepPart, 10) : 1;
    if (step < 1) throw new RangeError(`Field "${field}": step must be >= 1`);
    assertRange(lo, min, max, field);
    assertRange(hi, min, max, field);
    if (lo > hi) throw new RangeError(`Field "${field}": range start ${lo} > end ${hi}`);
    return expand(lo, hi, step);
  }

  // single number
  if (/^\d+$/.test(segment)) {
    const v = parseInt(segment, 10);
    assertRange(v, min, max, field);
    return [v];
  }

  throw new SyntaxError(`Field "${field}": unrecognised segment "${segment}"`);
}

function parseField(expr: string, field: CronField): number[] {
  if (!expr || expr.trim() === "")
    throw new SyntaxError(`Field "${field}": empty expression`);

  const parts = expr.split(",");
  const seen = new Set<number>();
  const values: number[] = [];

  for (const part of parts) {
    const trimmed = part.trim();
    if (!trimmed) throw new SyntaxError(`Field "${field}": empty segment in list`);
    for (const v of parseSegment(trimmed, field)) {
      if (!seen.has(v)) { seen.add(v); values.push(v); }
    }
  }

  return values.sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string")
    throw new TypeError("parseCron expects a string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(
      `parseCron expects 5 fields, got ${fields.length}: "${expression}"`
    );

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

interface QueueEntry {
  tokens: number;
  resolve: () => void;
}

export default class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;

  private currentTokens: number;
  private lastRefillTime: number;
  private readonly waitQueue: QueueEntry[];
  private timeoutHandle: ReturnType<typeof setTimeout> | null;

  constructor(options: RateLimiterOptions) {
    if (!Number.isFinite(options.maxTokens) || options.maxTokens <= 0) {
      throw new RangeError(`maxTokens must be a finite positive number, got ${options.maxTokens}`);
    }
    if (!Number.isFinite(options.refillRate) || options.refillRate < 0) {
      throw new RangeError(`refillRate must be a finite non-negative number, got ${options.refillRate}`);
    }
    if (!Number.isFinite(options.refillIntervalMs) || options.refillIntervalMs <= 0) {
      throw new RangeError(`refillIntervalMs must be a finite positive number, got ${options.refillIntervalMs}`);
    }

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
    this.waitQueue = [];
    this.timeoutHandle = null;
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;

    if (elapsed <= 0) return;

    const tokensToAdd = (elapsed / this.refillIntervalMs) * this.refillRate;
    this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
    this.lastRefillTime = now;
  }

  private scheduleNextCheck(): void {
    if (this.timeoutHandle !== null) return;
    if (this.waitQueue.length === 0) return;

    const next = this.waitQueue[0];
    const deficit = next.tokens - this.currentTokens;

    if (deficit <= 0) {
      this.drainQueue();
      return;
    }

    if (this.refillRate <= 0) {
      // No refill possible; waiters will block until reset() is called externally.
      return;
    }

    const msToFill = Math.ceil((deficit / this.refillRate) * this.refillIntervalMs);
    // Add a 1ms safety buffer to account for floating-point rounding and timer jitter.
    const delay = Math.max(1, msToFill + 1);

    this.timeoutHandle = setTimeout(() => {
      this.timeoutHandle = null;
      this.drainQueue();
    }, delay);
  }

  private drainQueue(): void {
    this.refill();

    while (this.waitQueue.length > 0) {
      const next = this.waitQueue[0];

      if (this.currentTokens >= next.tokens) {
        this.currentTokens -= next.tokens;
        this.waitQueue.shift();
        // Resolve after updating state so subsequent drainQueue calls see
        // the consumed tokens correctly even if resolve() re-enters synchronously.
        next.resolve();
      } else {
        this.scheduleNextCheck();
        break;
      }
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (!Number.isFinite(tokens) || tokens < 0) {
      throw new RangeError(`tokens must be a finite non-negative number, got ${tokens}`);
    }
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    if (this.timeoutHandle !== null) {
      clearTimeout(this.timeoutHandle);
      this.timeoutHandle = null;
    }

    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
    this.drainQueue();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (!Number.isFinite(tokens) || tokens < 0) {
      return Promise.reject(
        new RangeError(`tokens must be a finite non-negative number, got ${tokens}`)
      );
    }
    if (tokens > this.maxTokens) {
      return Promise.reject(
        new RangeError(
          `Requested ${tokens} tokens exceeds bucket capacity of ${this.maxTokens}; ` +
            `this promise would never resolve`
        )
      );
    }

    // Fast path: no queue ahead of us and enough tokens available.
    if (this.waitQueue.length === 0 && this.tryConsume(tokens)) {
      return Promise.resolve();
    }

    return new Promise<void>((resolve) => {
      this.waitQueue.push({ tokens, resolve });
      // Only schedule if this is the first entry (otherwise an existing
      // schedule is already in flight for the head of the queue).
      if (this.waitQueue.length === 1) {
        this.scheduleNextCheck();
      }
    });
  }
}

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute:     [0, 59],
  hour:       [0, 23],
  dayOfMonth: [1, 31],
  month:      [1, 12],
  dayOfWeek:  [0,  6],
};

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  }
  return val;
}

function parseField(expr: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // comma list — recurse, flatten, dedupe, sort
  if (expr.includes(",")) {
    const parts = expr.split(",");
    if (parts.some(p => p.trim() === "")) throw new SyntaxError(`Empty segment in list: "${expr}"`);
    const values = parts.flatMap(p => parseField(p.trim(), field));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // step: */n  or  a-b/n
  if (expr.includes("/")) {
    const [rangePart, stepPart] = expr.split("/");
    if (!stepPart || stepPart === "") throw new SyntaxError(`Missing step in: "${expr}"`);
    const step = Number(stepPart);
    if (!Number.isInteger(step) || step < 1) throw new RangeError(`Invalid step "${stepPart}" in: "${expr}"`);

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end   = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      if (!Number.isFinite(s) || !Number.isFinite(e)) throw new SyntaxError(`Bad range in: "${expr}"`);
      start = clamp(s, min, max);
      end   = clamp(e, min, max);
      if (start > end) throw new RangeError(`Range start > end in: "${expr}"`);
    } else {
      const n = Number(rangePart);
      if (!Number.isFinite(n)) throw new SyntaxError(`Bad value in: "${expr}"`);
      start = clamp(n, min, max);
      end   = max;
    }

    const result: number[] = [];
    for (let v = start; v <= end; v += step) result.push(v);
    return result;
  }

  // range: a-b
  if (expr.includes("-")) {
    const parts = expr.split("-");
    if (parts.length !== 2) throw new SyntaxError(`Invalid range: "${expr}"`);
    const [s, e] = parts.map(Number);
    if (!Number.isFinite(s) || !Number.isFinite(e)) throw new SyntaxError(`Non-numeric range: "${expr}"`);
    const start = clamp(s, min, max);
    const end   = clamp(e, min, max);
    if (start > end) throw new RangeError(`Range start > end: "${expr}"`);
    return Array.from({ length: end - start + 1 }, (_, i) => start + i);
  }

  // wildcard
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => min + i);
  }

  // single number
  const n = Number(expr);
  if (!Number.isFinite(n) || !Number.isInteger(n)) throw new SyntaxError(`Invalid value: "${expr}"`);
  return [clamp(n, min, max)];
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute:     parseField(minuteExpr, "minute"),
    hour:       parseField(hourExpr,   "hour"),
    dayOfMonth: parseField(domExpr,    "dayOfMonth"),
    month:      parseField(monthExpr,  "month"),
    dayOfWeek:  parseField(dowExpr,    "dayOfWeek"),
  };
}

type CronField = {
  values: number[];
};

type ParsedCron = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof ParsedCron, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 7],
};

function clamp(val: number, min: number, max: number): number {
  if (val < min || val > max) {
    throw new RangeError(`Value ${val} out of range [${min}, ${max}]`);
  }
  return val;
}

function parseField(expr: string, min: number, max: number): number[] {
  // comma list
  if (expr.includes(",")) {
    return expr
      .split(",")
      .flatMap((part) => parseField(part.trim(), min, max))
      .filter((v, i, a) => a.indexOf(v) === i)
      .sort((a, b) => a - b);
  }

  // wildcard
  if (expr === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // step: */n or range/n
  if (expr.includes("/")) {
    const [rangePart, stepStr] = expr.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step <= 0) throw new Error(`Invalid step: ${stepStr}`);

    let start = min;
    let end = max;

    if (rangePart !== "*") {
      if (rangePart.includes("-")) {
        const [lo, hi] = rangePart.split("-").map((n) => parseInt(n, 10));
        start = clamp(lo, min, max);
        end = clamp(hi, min, max);
      } else {
        start = clamp(parseInt(rangePart, 10), min, max);
      }
    }

    const result: number[] = [];
    for (let i = start; i <= end; i += step) result.push(i);
    return result;
  }

  // range: a-b
  if (expr.includes("-")) {
    const [lo, hi] = expr.split("-").map((n) => parseInt(n, 10));
    const start = clamp(lo, min, max);
    const end = clamp(hi, min, max);
    if (start > end) throw new Error(`Invalid range: ${expr}`);
    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // single number
  const num = parseInt(expr, 10);
  if (isNaN(num)) throw new Error(`Invalid cron token: ${expr}`);
  return [clamp(num, min, max)];
}

export default function parseCron(expression: string): ParsedCron {
  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}`);
  }

  const keys = Object.keys(FIELD_RANGES) as (keyof ParsedCron)[];
  const result = {} as ParsedCron;

  for (let i = 0; i < 5; i++) {
    const key = keys[i];
    const [min, max] = FIELD_RANGES[key];
    let values = parseField(fields[i], min, max);

    // normalize dayOfWeek: 7 -> 0 (both = Sunday)
    if (key === "dayOfWeek") {
      values = values.map((v) => (v === 7 ? 0 : v));
      values = [...new Set(values)].sort((a, b) => a - b);
    }

    result[key] = values;
  }

  return result;
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key in obj) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? (val as unknown as Primitive) : (val as Primitive);
    }
  }
  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || obj === undefined || typeof obj !== "object") {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  if (Array.isArray(obj)) {
    if (prefix) result[prefix] = JSON.stringify(obj);
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = "{}";
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const sanitizedKey = String(key);
    const newKey = prefix ? `${prefix}.${sanitizedKey}` : sanitizedKey;
    const value = obj[key];

    if (
      value !== null &&
      value !== undefined &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else if (Array.isArray(value)) {
      result[newKey] = JSON.stringify(value);
    } else {
      result[newKey] = value as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | unknown[] };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    if (!Object.prototype.hasOwnProperty.call(obj, key)) continue;

    const safeKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val as object).length > 0
    ) {
      flattenObject(val as NestedObject, safeKey, result);
    } else {
      result[safeKey] = val as Primitive;
    }
  }

  return result;
}

export default flattenObject;

type CronField = {
  min: number;
  max: number;
};

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, CronField> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

const FIELD_NAMES = ["minute", "hour", "dayOfMonth", "month", "dayOfWeek"] as const;

function validateValue(value: number, field: keyof CronResult): number {
  const { min, max } = FIELD_RANGES[field];
  if (value < min || value > max) {
    throw new RangeError(
      `Value ${value} is out of range [${min}-${max}] for field "${field}"`
    );
  }
  return value;
}

function parseToken(token: string, field: keyof CronResult): number[] {
  const { min, max } = FIELD_RANGES[field];

  // Wildcard: *
  if (token === "*") {
    return Array.from({ length: max - min + 1 }, (_, i) => i + min);
  }

  // Step: */n or range/n
  if (token.includes("/")) {
    const [rangePart, stepPart] = token.split("/");
    const step = parseInt(stepPart, 10);

    if (isNaN(step) || step <= 0) {
      throw new SyntaxError(`Invalid step value in token "${token}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-").map(Number);
      start = validateValue(s, field);
      end = validateValue(e, field);
      if (start > end) throw new RangeError(`Invalid range "${rangePart}" in field "${field}"`);
    } else {
      start = validateValue(parseInt(rangePart, 10), field);
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: n-m
  if (token.includes("-")) {
    const [startStr, endStr] = token.split("-");
    const start = validateValue(parseInt(startStr, 10), field);
    const end = validateValue(parseInt(endStr, 10), field);

    if (start > end) {
      throw new RangeError(`Invalid range "${token}" in field "${field}"`);
    }

    return Array.from({ length: end - start + 1 }, (_, i) => i + start);
  }

  // Plain number
  const value = parseInt(token, 10);
  if (isNaN(value)) {
    throw new SyntaxError(`Invalid token "${token}" in field "${field}"`);
  }
  return [validateValue(value, field)];
}

function parseField(expression: string, field: keyof CronResult): number[] {
  // Normalize dayOfWeek: map 7 -> 0 (both represent Sunday)
  const tokens = expression.split(",");
  const allValues = new Set<number>();

  for (const token of tokens) {
    const values = parseToken(token.trim(), field);
    for (const v of values) {
      // Normalize Sunday: 7 -> 0
      allValues.add(field === "dayOfWeek" && v === 7 ? 0 : v);
    }
  }

  return Array.from(allValues).sort((a, b) => a - b);
}

export function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") {
    throw new TypeError("Cron expression must be a string");
  }

  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new SyntaxError(
      `Cron expression must have exactly 5 fields, got ${fields.length}`
    );
  }

  const result = {} as CronResult;

  for (let i = 0; i < FIELD_NAMES.length; i++) {
    const fieldName = FIELD_NAMES[i];
    result[fieldName] = parseField(fields[i], fieldName);
  }

  return result;
}

export default parseCron;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(val: number, min: number, max: number, ctx: string): void {
  if (val < min || val > max)
    throw new RangeError(`${ctx}: ${val} out of [${min},${max}]`);
}

function parseSegment(segment: string, field: CronField): number[] {
  const [min, max] = FIELD_RANGES[field];

  // wildcard
  if (segment === "*") return range(min, max);

  // step: */n or start-end/n
  if (segment.includes("/")) {
    const [left, stepStr] = segment.split("/");
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1)
      throw new RangeError(`${field}: invalid step "${stepStr}"`);

    let base: number[];
    if (left === "*") {
      base = range(min, max);
    } else if (left.includes("-")) {
      const [s, e] = left.split("-").map(Number);
      assertInRange(s, min, max, field);
      assertInRange(e, min, max, field);
      base = range(s, e);
    } else {
      const start = parseInt(left, 10);
      assertInRange(start, min, max, field);
      base = range(start, max);
    }
    return base.filter((v) => (v - base[0]) % step === 0);
  }

  // range: a-b
  if (segment.includes("-")) {
    const parts = segment.split("-");
    if (parts.length !== 2) throw new SyntaxError(`${field}: invalid range "${segment}"`);
    const [s, e] = parts.map(Number);
    if (isNaN(s) || isNaN(e)) throw new SyntaxError(`${field}: non-numeric range "${segment}"`);
    assertInRange(s, min, max, field);
    assertInRange(e, min, max, field);
    return range(s, e);
  }

  // single number
  const val = parseInt(segment, 10);
  if (isNaN(val)) throw new SyntaxError(`${field}: invalid value "${segment}"`);
  assertInRange(val, min, max, field);
  return [val];
}

function parseField(expr: string, field: CronField): number[] {
  const segments = expr.split(",");
  if (segments.length === 0) throw new SyntaxError(`${field}: empty expression`);

  const values = new Set<number>();
  for (const seg of segments) {
    for (const v of parseSegment(seg.trim(), field)) {
      values.add(v);
    }
  }
  return Array.from(values).sort((a, b) => a - b);
}

export default function parseCron(expression: string): CronResult {
  if (typeof expression !== "string") throw new TypeError("Expression must be string");

  const fields = expression.trim().split(/\s+/);
  if (fields.length !== 5)
    throw new SyntaxError(`Expected 5 fields, got ${fields.length}`);

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  return {
    minute: parseField(minuteExpr, "minute"),
    hour: parseField(hourExpr, "hour"),
    dayOfMonth: parseField(domExpr, "dayOfMonth"),
    month: parseField(monthExpr, "month"),
    dayOfWeek: parseField(dowExpr, "dayOfWeek"),
  };
}

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  for (const key of Object.keys(obj)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const val = obj[key];

    if (
      val !== null &&
      typeof val === "object" &&
      !Array.isArray(val) &&
      Object.keys(val).length > 0
    ) {
      flattenObject(val as NestedObject, fullKey, result);
    } else {
      result[fullKey] = Array.isArray(val) ? (JSON.stringify(val) as Primitive) : (val as Primitive);
    }
  }
  return result;
}

export default flattenObject;

type CronField = "minute" | "hour" | "dayOfMonth" | "month" | "dayOfWeek";

interface CronResult {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
}

const FIELD_RANGES: Record<CronField, { min: number; max: number }> = {
  minute:     { min: 0,  max: 59 },
  hour:       { min: 0,  max: 23 },
  dayOfMonth: { min: 1,  max: 31 },
  month:      { min: 1,  max: 12 },
  dayOfWeek:  { min: 0,  max: 7  },
};

function rangeArray(min: number, max: number, step = 1): number[] {
  if (step < 1) throw new Error(`Step must be >= 1, got ${step}`);
  const result: number[] = [];
  for (let i = min; i <= max; i += step) {
    result.push(i);
  }
  return result;
}

function parseSegment(segment: string, field: CronField): number[] {
  const { min, max } = FIELD_RANGES[field];

  const validateValue = (value: number): number => {
    if (value < min || value > max) {
      throw new Error(
        `Value ${value} out of range [${min}, ${max}] for field "${field}"`
      );
    }
    return value;
  };

  // Wildcard: "*"
  if (segment === "*") {
    return rangeArray(min, max);
  }

  // Step with wildcard: "*/N"
  if (/^\*\/\d+$/.test(segment)) {
    const step = parseInt(segment.slice(2), 10);
    return rangeArray(min, max, step);
  }

  // Range with optional step: "N-M" or "N-M/S"
  if (/^\d+-\d+(\/\d+)?$/.test(segment)) {
    const [rangePart, stepPart] = segment.split("/");
    const [startStr, endStr] = rangePart.split("-");
    const start = validateValue(parseInt(startStr, 10));
    const end = validateValue(parseInt(endStr, 10));
    if (start > end) {
      throw new Error(
        `Range start ${start} must be <= end ${end} for field "${field}"`
      );
    }
    const step = stepPart !== undefined ? parseInt(stepPart, 10) : 1;
    return rangeArray(start, end, step);
  }

  // Comma-separated list: "N,M,..."
  if (/^[\d,]+$/.test(segment)) {
    const values = segment.split(",").map((v) => validateValue(parseInt(v, 10)));
    return [...new Set(values)].sort((a, b) => a - b);
  }

  // Single number
  if (/^\d+$/.test(segment)) {
    return [validateValue(parseInt(segment, 10))];
  }

  throw new Error(`Invalid cron segment "${segment}" for field "${field}"`);
}

function normalizeDayOfWeek(values: number[]): number[] {
  // Treat 7 as Sunday (0) — both are valid
  const normalized = values.map((v) => (v === 7 ? 0 : v));
  return [...new Set(normalized)].sort((a, b) => a - b);
}

function parseCron(expression: string): CronResult {
  const fields = expression.trim().split(/\s+/);

  if (fields.length !== 5) {
    throw new Error(
      `Expected 5 cron fields, got ${fields.length}: "${expression}"`
    );
  }

  const [minuteExpr, hourExpr, domExpr, monthExpr, dowExpr] = fields;

  const rawDayOfWeek = parseSegment(dowExpr, "dayOfWeek");

  return {
    minute:     parseSegment(minuteExpr, "minute"),
    hour:       parseSegment(hourExpr,   "hour"),
    dayOfMonth: parseSegment(domExpr,    "dayOfMonth"),
    month:      parseSegment(monthExpr,  "month"),
    dayOfWeek:  normalizeDayOfWeek(rawDayOfWeek),
  };
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined | symbol | bigint;
type FlatRecord = Record<string, Primitive | Date | RegExp | unknown[]>;

function isPlainObject(value: unknown): value is Record<string, unknown> {
  if (value === null || typeof value !== "object") return false;
  if (value instanceof Date) return false;
  if (value instanceof RegExp) return false;
  if (value instanceof Map) return false;
  if (value instanceof Set) return false;
  if (ArrayBuffer.isView(value)) return false;
  return true;
}

function flattenObject(
  input: Record<string, unknown>,
  prefix = "",
  seen = new WeakSet<object>()
): FlatRecord {
  if (!isPlainObject(input)) {
    throw new TypeError("Input must be a plain object");
  }

  const result: FlatRecord = {};

  if (seen.has(input)) {
    throw new Error(`Circular reference detected at key: "${prefix}"`);
  }

  seen.add(input);

  for (const key of Object.keys(input)) {
    const fullKey = prefix ? `${prefix}.${key}` : key;
    const value = input[key];

    if (isPlainObject(value)) {
      const nested = flattenObject(value, fullKey, seen);
      // If nested object is empty, preserve the key with an empty-object sentinel
      if (Object.keys(nested).length === 0) {
        result[fullKey] = {} as unknown as FlatRecord[string];
      } else {
        Object.assign(result, nested);
      }
    } else {
      result[fullKey] = value as FlatRecord[string];
    }
  }

  seen.delete(input);

  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private currentTokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.currentTokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      const tokensToAdd = intervals * this.refillRate;
      this.currentTokens = Math.min(this.maxTokens, this.currentTokens + tokensToAdd);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.currentTokens >= tokens) {
      this.currentTokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.currentTokens;
  }

  reset(): void {
    this.currentTokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  async waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) {
      throw new RangeError(`Requested tokens (${tokens}) exceed maxTokens (${this.maxTokens})`);
    }

    while (!this.tryConsume(tokens)) {
      const waitMs = this.estimateWaitMs(tokens);
      await new Promise<void>((resolve) => setTimeout(resolve, waitMs));
    }
  }

  private estimateWaitMs(tokens: number): number {
    this.refill();
    const deficit = tokens - this.currentTokens;

    if (deficit <= 0) return 0;

    const intervalsNeeded = Math.ceil(deficit / this.refillRate);
    const elapsed = Date.now() - this.lastRefillTime;
    const timeUntilNextInterval = this.refillIntervalMs - (elapsed % this.refillIntervalMs);

    return timeUntilNextInterval + (intervalsNeeded - 1) * this.refillIntervalMs;
  }
}

export default RateLimiter;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens = 1): Promise<void> {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens"));

    return new Promise((resolve) => {
      const attempt = (): void => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msUntilNext = this.refillIntervalMs - (Date.now() - this.lastRefillTime);
        const delay = msUntilNext + (intervalsNeeded - 1) * this.refillIntervalMs;

        setTimeout(attempt, Math.max(0, delay));
      };

      attempt();
    });
  }
}

export default RateLimiter;

type CronResult = {
  minute: number[];
  hour: number[];
  dayOfMonth: number[];
  month: number[];
  dayOfWeek: number[];
};

const FIELD_RANGES: Record<keyof CronResult, [number, number]> = {
  minute: [0, 59],
  hour: [0, 23],
  dayOfMonth: [1, 31],
  month: [1, 12],
  dayOfWeek: [0, 6],
};

function range(start: number, end: number): number[] {
  if (start > end) throw new RangeError(`Invalid range: ${start}-${end}`);
  return Array.from({ length: end - start + 1 }, (_, i) => start + i);
}

function assertInRange(value: number, min: number, max: number, context: string): void {
  if (value < min || value > max) {
    throw new RangeError(`Value ${value} out of range [${min}, ${max}] in field "${context}"`);
  }
}

function parseField(expression: string, min: number, max: number, fieldName: string): number[] {
  // Comma-separated list
  if (expression.includes(",")) {
    const parts = expression.split(",");
    const values = new Set<number>();
    for (const part of parts) {
      for (const v of parseField(part.trim(), min, max, fieldName)) {
        values.add(v);
      }
    }
    return [...values].sort((a, b) => a - b);
  }

  // Wildcard
  if (expression === "*") {
    return range(min, max);
  }

  // Step value: */step or start-end/step
  if (expression.includes("/")) {
    const [rangePart, stepStr] = expression.split("/", 2);
    const step = parseInt(stepStr, 10);
    if (isNaN(step) || step < 1) {
      throw new RangeError(`Invalid step value "${stepStr}" in field "${fieldName}"`);
    }

    let start: number;
    let end: number;

    if (rangePart === "*") {
      start = min;
      end = max;
    } else if (rangePart.includes("-")) {
      const [s, e] = rangePart.split("-", 2).map(Number);
      if (isNaN(s) || isNaN(e)) {
        throw new RangeError(`Invalid range "${rangePart}" in field "${fieldName}"`);
      }
      assertInRange(s, min, max, fieldName);
      assertInRange(e, min, max, fieldName);
      start = s;
      end = e;
    } else {
      const s = parseInt(rangePart, 10);
      if (isNaN(s)) {
        throw new RangeError(`Invalid expression "${expression}" in field "${fieldName}"`);
      }
      assertInRange(s, min, max, fieldName);
      start = s;
      end = max;
    }

    const values: number[] = [];
    for (let i = start; i <= end; i += step) {
      values.push(i);
    }
    return values;
  }

  // Range: start-end
  if (expression.includes("-")) {
    const [startStr, endStr] = expression.split("-", 2);
    const start = parseInt(startStr, 10);
    const end = parseInt(endStr, 10);
    if (isNaN(start) || isNaN(end)) {
      throw new RangeError(`Invalid range "${expression}" in field "${fieldName}"`);
    }
    assertInRange(start, min, max, fieldName);
    assertInRange(end, min, max, fieldName);
    return range(start, end);
  }

  // Single number
  const value = parseInt(expression, 10);
  if (isNaN(value)) {
    throw new RangeError(`Invalid value "${expression}" in field "${fieldName}"`);
  }
  assertInRange(value, min, max, fieldName);
  return [value];
}

function parseCron(expression: string): CronResult {
  const trimmed = expression.trim().replace(/\s+/g, " ");
  const fields = trimmed.split(" ");

  if (fields.length !== 5) {
    throw new Error(`Expected 5 fields, got ${fields.length}: "${expression}"`);
  }

  const [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr] = fields;
  const fieldNames = Object.keys(FIELD_RANGES) as (keyof CronResult)[];
  const expressions = [minuteExpr, hourExpr, dayOfMonthExpr, monthExpr, dayOfWeekExpr];

  const result = {} as CronResult;

  for (let i = 0; i < fieldNames.length; i++) {
    const name = fieldNames[i];
    const [min, max] = FIELD_RANGES[name];
    result[name] = parseField(expressions[i], min, max, name);
  }

  return result;
}

export default parseCron;

type Primitive = string | number | boolean | null | undefined;
type NestedObject = { [key: string]: Primitive | NestedObject | Array<unknown> };
type FlatObject = { [key: string]: Primitive };

function flattenObject(
  obj: NestedObject,
  prefix = "",
  result: FlatObject = {}
): FlatObject {
  if (obj === null || typeof obj !== "object" || Array.isArray(obj)) {
    if (prefix) result[prefix] = obj as Primitive;
    return result;
  }

  const keys = Object.keys(obj);

  if (keys.length === 0) {
    if (prefix) result[prefix] = {} as unknown as Primitive;
    return result;
  }

  for (const key of keys) {
    const newKey = prefix ? `${prefix}.${key}` : key;
    const value = obj[key];

    if (
      value !== null &&
      typeof value === "object" &&
      !Array.isArray(value)
    ) {
      flattenObject(value as NestedObject, newKey, result);
    } else {
      result[newKey] = Array.isArray(value)
        ? (JSON.stringify(value) as Primitive)
        : (value as Primitive);
    }
  }

  return result;
}

export default flattenObject;

export interface RateLimiterOptions {
  maxTokens: number;
  refillRate: number;
  refillIntervalMs: number;
}

export class RateLimiter {
  private readonly maxTokens: number;
  private readonly refillRate: number;
  private readonly refillIntervalMs: number;
  private tokens: number;
  private lastRefillTime: number;

  constructor(options: RateLimiterOptions) {
    if (options.maxTokens <= 0) throw new RangeError("maxTokens must be > 0");
    if (options.refillRate <= 0) throw new RangeError("refillRate must be > 0");
    if (options.refillIntervalMs <= 0) throw new RangeError("refillIntervalMs must be > 0");

    this.maxTokens = options.maxTokens;
    this.refillRate = options.refillRate;
    this.refillIntervalMs = options.refillIntervalMs;
    this.tokens = options.maxTokens;
    this.lastRefillTime = Date.now();
  }

  private refill(): void {
    const now = Date.now();
    const elapsed = now - this.lastRefillTime;
    const intervals = Math.floor(elapsed / this.refillIntervalMs);

    if (intervals > 0) {
      this.tokens = Math.min(this.maxTokens, this.tokens + intervals * this.refillRate);
      this.lastRefillTime += intervals * this.refillIntervalMs;
    }
  }

  tryConsume(tokens: number = 1): boolean {
    if (tokens <= 0) throw new RangeError("tokens must be > 0");
    if (tokens > this.maxTokens) return false;

    this.refill();

    if (this.tokens >= tokens) {
      this.tokens -= tokens;
      return true;
    }

    return false;
  }

  getTokens(): number {
    this.refill();
    return this.tokens;
  }

  reset(): void {
    this.tokens = this.maxTokens;
    this.lastRefillTime = Date.now();
  }

  waitForTokens(tokens: number = 1): Promise<void> {
    if (tokens <= 0) return Promise.reject(new RangeError("tokens must be > 0"));
    if (tokens > this.maxTokens) return Promise.reject(new RangeError("tokens exceeds maxTokens — will never be satisfiable"));

    return new Promise((resolve) => {
      const attempt = () => {
        if (this.tryConsume(tokens)) {
          resolve();
          return;
        }

        this.refill();
        const deficit = tokens - this.tokens;
        const intervalsNeeded = Math.ceil(deficit / this.refillRate);
        const msUntilSufficient = intervalsNeeded * this.refillIntervalMs;
        const remainderMs = this.refillIntervalMs - (Date.now() - this.lastRefillTime) % this.refillIntervalMs;
        const delay = Math.max(0, msUntilSufficient - this.refillIntervalMs + remainderMs);

        setTimeout(attempt, delay);
      };

      attempt();
    });
  }
}

export default RateLimiter;
